var VERSES_MARK=[{"ref":"Mark 1:1","short":"Mar 1:1","text":"The beginning of the good news about Jesus the Messiah, the Son of God,","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":1},{"ref":"Mark 1:2","short":"Mar 1:2","text":"as it is written in Isaiah the prophet: \u201cI will send my messenger ahead of you, who will prepare your way\u201d\u2014","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":2},{"ref":"Mark 1:3","short":"Mar 1:3","text":"\u201ca voice of one calling in the wilderness, \u201cPrepare the way for the Lord, make straight paths for him.\u201d\u2019","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":3},{"ref":"Mark 1:4","short":"Mar 1:4","text":"And so John the Baptist appeared in the wilderness, preaching a baptism of repentance for the forgiveness of sins.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":4},{"ref":"Mark 1:5","short":"Mar 1:5","text":"The whole Judean countryside and all the people of Jerusalem went out to him. Confessing their sins, they were baptized by him in the Jordan River.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":5},{"ref":"Mark 1:6","short":"Mar 1:6","text":"John wore clothing made of camel\u2019s hair, with a leather belt around his waist, and he ate locusts and wild honey.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":6},{"ref":"Mark 1:7","short":"Mar 1:7","text":"And this was his message: \u201cAfter me comes the one more powerful than I, the straps of whose sandals I am not worthy to stoop down and untie.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":7},{"ref":"Mark 1:8","short":"Mar 1:8","text":"I baptize you with water, but he will baptize you with the Holy Spirit.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":8},{"ref":"Mark 1:9","short":"Mar 1:9","text":"At that time Jesus came from Nazareth in Galilee and was baptized by John in the Jordan.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":9},{"ref":"Mark 1:10","short":"Mar 1:10","text":"Just as Jesus was coming up out of the water, he saw heaven being torn open and the Spirit descending on him like a dove.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":10},{"ref":"Mark 1:11","short":"Mar 1:11","text":"And a voice came from heaven: \u201cYou are my Son, whom I love; with you I am well pleased.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":11},{"ref":"Mark 1:12","short":"Mar 1:12","text":"At once the Spirit sent him out into the wilderness,","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":12},{"ref":"Mark 1:13","short":"Mar 1:13","text":"and he was in the wilderness forty days, being tempted by Satan. He was with the wild animals, and angels attended him.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":13},{"ref":"Mark 1:14","short":"Mar 1:14","text":"After John was put in prison, Jesus went into Galilee, proclaiming the good news of God.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":14},{"ref":"Mark 1:15","short":"Mar 1:15","text":"\u201cThe time has come,\u201d he said. \u201cThe kingdom of God has come near. Repent and believe the good news!\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":15},{"ref":"Mark 1:16","short":"Mar 1:16","text":"As Jesus walked along the shore of the Sea of Galilee, he saw Simon and his brother Andrew casting a net into the lake, for they were fishermen.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":16},{"ref":"Mark 1:17","short":"Mar 1:17","text":"\u201cCome, follow me,\u201d Jesus said, \u201cand I will send you out to fish for people.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":17},{"ref":"Mark 1:18","short":"Mar 1:18","text":"At once they left their nets and followed him.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":18},{"ref":"Mark 1:19","short":"Mar 1:19","text":"When he had gone a little farther, he saw James son of Zebedee and his brother John in a boat, preparing their nets.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":19},{"ref":"Mark 1:20","short":"Mar 1:20","text":"Without delay he called them, and they left their father Zebedee in the boat with the hired men and followed him.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":20},{"ref":"Mark 1:21","short":"Mar 1:21","text":"They went to Capernaum, and when the Sabbath came, Jesus went into the synagogue and began to teach.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":21},{"ref":"Mark 1:22","short":"Mar 1:22","text":"The people were amazed at his teaching, because he taught them as one who had authority, not as the teachers of the law.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":22},{"ref":"Mark 1:23","short":"Mar 1:23","text":"Just then a man in their synagogue who was possessed by an impure spirit cried out,","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":23},{"ref":"Mark 1:24","short":"Mar 1:24","text":"\u201cWhat do you want with us, Jesus of Nazareth? Have you come to destroy us? I know who you are\u2014the Holy One of God!\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":24},{"ref":"Mark 1:25","short":"Mar 1:25","text":"\u201cBe quiet!\u201d said Jesus sternly. \u201cCome out of him!\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":25},{"ref":"Mark 1:26","short":"Mar 1:26","text":"The impure spirit shook the man violently and came out of him with a shriek.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":26},{"ref":"Mark 1:27","short":"Mar 1:27","text":"The people were all so amazed that they asked each other, \u201cWhat is this? A new teaching\u2014and with authority! He even gives orders to impure spirits and they obey him.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":27},{"ref":"Mark 1:28","short":"Mar 1:28","text":"News about him spread quickly over the whole region of Galilee.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":28},{"ref":"Mark 1:29","short":"Mar 1:29","text":"As soon as they left the synagogue, they went with James and John to the home of Simon and Andrew.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":29},{"ref":"Mark 1:30","short":"Mar 1:30","text":"Simon\u2019s mother-in-law was in bed with a fever, and they immediately told Jesus about her.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":30},{"ref":"Mark 1:31","short":"Mar 1:31","text":"So he went to her, took her by the hand and helped her up. The fever left her and she began to wait on them.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":31},{"ref":"Mark 1:32","short":"Mar 1:32","text":"That evening after sunset the people brought to Jesus all the sick and demon-possessed.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":32},{"ref":"Mark 1:33","short":"Mar 1:33","text":"The whole town gathered at the door,","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":33},{"ref":"Mark 1:34","short":"Mar 1:34","text":"and Jesus healed many who had various diseases. He also drove out many demons, but he would not let the demons speak because they knew who he was.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":34},{"ref":"Mark 1:35","short":"Mar 1:35","text":"Very early in the morning, while it was still dark, Jesus got up, left the house and went off to a solitary place, where he prayed.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":35},{"ref":"Mark 1:36","short":"Mar 1:36","text":"Simon and his companions went to look for him,","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":36},{"ref":"Mark 1:37","short":"Mar 1:37","text":"and when they found him, they exclaimed: \u201cEveryone is looking for you!\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":37},{"ref":"Mark 1:38","short":"Mar 1:38","text":"\u201cLet us go somewhere else\u2014to the nearby villages\u2014so I can preach there also. That is why I have come.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":38},{"ref":"Mark 1:39","short":"Mar 1:39","text":"So he traveled throughout Galilee, preaching in their synagogues and driving out demons.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":39},{"ref":"Mark 1:40","short":"Mar 1:40","text":"A man with leprosy came to him and begged him on his knees, \u201cIf you are willing, you can make me clean.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":40},{"ref":"Mark 1:41","short":"Mar 1:41","text":"Jesus was indignant. He reached out his hand and touched him. \u201cI am willing,\u201d he said. \u201cBe clean!\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":41},{"ref":"Mark 1:42","short":"Mar 1:42","text":"Immediately the leprosy left him and he was cleansed.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":42},{"ref":"Mark 1:43","short":"Mar 1:43","text":"Jesus sent him away at once with a strong warning:","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":43},{"ref":"Mark 1:44","short":"Mar 1:44","text":"\u201cSee that you tell no one. But go, show yourself to the priest and offer the sacrifices that Moses commanded for your cleansing, as a testimony to them.\u201d","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":44},{"ref":"Mark 1:45","short":"Mar 1:45","text":"Instead he went out and began to talk freely, spreading the news. As a result, Jesus could no longer enter a town openly but stayed outside in lonely places. Yet the people still came to him from everywhere.","url":"nt/mark/Mark_1.html","book":"Mark","ch":1,"v":45},{"ref":"Mark 2:1","short":"Mar 2:1","text":"A few days later, when Jesus again entered Capernaum, the people heard that he had come home.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":1},{"ref":"Mark 2:2","short":"Mar 2:2","text":"They gathered in such large numbers that there was no room left, not even outside the door, and he preached the word to them.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":2},{"ref":"Mark 2:3","short":"Mar 2:3","text":"Some men came, bringing to him a paralyzed man, carried by four of them.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":3},{"ref":"Mark 2:4","short":"Mar 2:4","text":"Since they could not get him to Jesus because of the crowd, they made an opening in the roof above Jesus by digging through it and then lowered the mat the man was lying on.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":4},{"ref":"Mark 2:5","short":"Mar 2:5","text":"When Jesus saw their faith, he said to the paralyzed man, \u201cSon, your sins are forgiven.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":5},{"ref":"Mark 2:6","short":"Mar 2:6","text":"Now some teachers of the law were sitting there, thinking to themselves,","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":6},{"ref":"Mark 2:7","short":"Mar 2:7","text":"\u201cWhy does this fellow talk like that? He\u2019s blaspheming! Who can forgive sins but God alone?\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":7},{"ref":"Mark 2:8","short":"Mar 2:8","text":"Immediately Jesus knew in his spirit that this was what they were thinking in their hearts, and he said to them, \u201cWhy are you thinking these things?","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":8},{"ref":"Mark 2:9","short":"Mar 2:9","text":"Which is easier: to say to this paralyzed man, \u201cYour sins are forgiven,\u201d or to say, \u201cGet up, take your mat and walk\u201d?","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":9},{"ref":"Mark 2:10","short":"Mar 2:10","text":"But I want you to know that the Son of Man has authority on earth to forgive sins.\u201d So he said to the man,","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":10},{"ref":"Mark 2:11","short":"Mar 2:11","text":"\u201cI tell you, get up, take your mat and go home.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":11},{"ref":"Mark 2:12","short":"Mar 2:12","text":"He got up, took his mat and walked out in full view of them all. This amazed everyone and they praised God, saying, \u201cWe have never seen anything like this!\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":12},{"ref":"Mark 2:13","short":"Mar 2:13","text":"Once again Jesus went out beside the lake; a large crowd came to him, and he began to teach them.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":13},{"ref":"Mark 2:14","short":"Mar 2:14","text":"As he walked along, he saw Levi son of Alphaeus sitting at the tax collector\u2019s booth. \u201cFollow me,\u201d Jesus said to him. And Levi got up and followed him.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":14},{"ref":"Mark 2:15","short":"Mar 2:15","text":"While Jesus was having dinner at Levi\u2019s house, many tax collectors and sinners were eating with him and his disciples, for there were many who followed him.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":15},{"ref":"Mark 2:16","short":"Mar 2:16","text":"When the teachers of the law who were Pharisees saw him eating with sinners and tax collectors, they asked his disciples: \u201cWhy does he eat with tax collectors and sinners?\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":16},{"ref":"Mark 2:17","short":"Mar 2:17","text":"On hearing this, Jesus said to them, \u201cIt is not the healthy who need a doctor, but the sick. I have not come to call the righteous, but sinners.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":17},{"ref":"Mark 2:18","short":"Mar 2:18","text":"Now John\u2019s disciples and the Pharisees were fasting. Some people came and asked Jesus, \u201cHow is it that John\u2019s disciples and the disciples of the Pharisees fast, but yours do not?\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":18},{"ref":"Mark 2:19","short":"Mar 2:19","text":"Jesus answered, \u201cHow can the guests of the bridegroom fast while he is with them? They cannot, so long as they have him with them.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":19},{"ref":"Mark 2:20","short":"Mar 2:20","text":"But the time will come when the bridegroom will be taken from them, and on that day they will fast.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":20},{"ref":"Mark 2:21","short":"Mar 2:21","text":"\u201cNo one sews a patch of unshrunk cloth on an old garment. Otherwise, the new piece will pull away from the old, making the tear worse.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":21},{"ref":"Mark 2:22","short":"Mar 2:22","text":"And no one pours new wine into old wineskins. If he does, the wine will burst the skins, and both the wine and the wineskins will be ruined. No, they pour new wine into new wineskins.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":22},{"ref":"Mark 2:23","short":"Mar 2:23","text":"One Sabbath Jesus was going through the grainfields, and as his disciples walked along, they began to pick some heads of grain.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":23},{"ref":"Mark 2:24","short":"Mar 2:24","text":"The Pharisees said to him, \u201cLook, why are they doing what is unlawful on the Sabbath?\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":24},{"ref":"Mark 2:25","short":"Mar 2:25","text":"He answered, \u201cHave you never read what David did when he and his companions were hungry and in need?","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":25},{"ref":"Mark 2:26","short":"Mar 2:26","text":"In the days of Abiathar the high priest, he entered the house of God and ate the consecrated bread, which is lawful only for priests to eat. And he also gave some to his companions.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":26},{"ref":"Mark 2:27","short":"Mar 2:27","text":"Then he said to them, \u201cThe Sabbath was made for man, not man for the Sabbath.","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":27},{"ref":"Mark 2:28","short":"Mar 2:28","text":"So the Son of Man is Lord even of the Sabbath.\u201d","url":"nt/mark/Mark_2.html","book":"Mark","ch":2,"v":28},{"ref":"Mark 3:1","short":"Mar 3:1","text":"Another time Jesus went into the synagogue, and a man with a shriveled hand was there.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":1},{"ref":"Mark 3:2","short":"Mar 3:2","text":"Some of them were looking for a reason to accuse Jesus, so they watched him closely to see if he would heal him on the Sabbath.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":2},{"ref":"Mark 3:3","short":"Mar 3:3","text":"Jesus said to the man with the shriveled hand, \u201cStand up in front of everyone.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":3},{"ref":"Mark 3:4","short":"Mar 3:4","text":"Then Jesus asked them, \u201cWhich is lawful on the Sabbath: to do good or to do evil, to save life or to kill?\u201d But they remained silent.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":4},{"ref":"Mark 3:5","short":"Mar 3:5","text":"He looked around at them in anger and, deeply distressed at their stubborn hearts, said to the man, \u201cStretch out your hand.\u201d He stretched it out, and his hand was completely restored.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":5},{"ref":"Mark 3:6","short":"Mar 3:6","text":"Then the Pharisees went out and began to plot with the Herodians how they might kill Jesus.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":6},{"ref":"Mark 3:7","short":"Mar 3:7","text":"Jesus withdrew with his disciples to the lake, and a large crowd from Galilee followed.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":7},{"ref":"Mark 3:8","short":"Mar 3:8","text":"When they heard about all he was doing, people came to him from Judea, Jerusalem, Idumea, and the regions across the Jordan and around Tyre and Sidon.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":8},{"ref":"Mark 3:9","short":"Mar 3:9","text":"Because of the crowd he told his disciples to have a small boat ready for him, to keep the people from crowding him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":9},{"ref":"Mark 3:10","short":"Mar 3:10","text":"For he had healed many, so that those with diseases were pushing forward to touch him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":10},{"ref":"Mark 3:11","short":"Mar 3:11","text":"Whenever the impure spirits saw him, they fell down before him and cried out, \u201cYou are the Son of God.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":11},{"ref":"Mark 3:12","short":"Mar 3:12","text":"But he gave them strict orders not to tell anyone about him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":12},{"ref":"Mark 3:13","short":"Mar 3:13","text":"Jesus went up on a mountainside and called to him those he wanted, and they came to him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":13},{"ref":"Mark 3:14","short":"Mar 3:14","text":"He appointed twelve that they might be with him and that he might send them out to preach","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":14},{"ref":"Mark 3:15","short":"Mar 3:15","text":"and to have authority to drive out demons.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":15},{"ref":"Mark 3:16","short":"Mar 3:16","text":"These are the twelve he appointed: Simon (to whom he gave the name Peter),","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":16},{"ref":"Mark 3:17","short":"Mar 3:17","text":"James son of Zebedee and his brother John (to them he gave the name Boanerges, which means \u201cSons of Thunder\u201d),","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":17},{"ref":"Mark 3:18","short":"Mar 3:18","text":"Andrew, Philip, Bartholomew, Matthew, Thomas, James son of Alphaeus, Thaddaeus, Simon the Zealot","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":18},{"ref":"Mark 3:19","short":"Mar 3:19","text":"and Judas Iscariot, who betrayed him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":19},{"ref":"Mark 3:20","short":"Mar 3:20","text":"Then Jesus entered a house, and again a crowd gathered, so that he and his disciples were not even able to eat.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":20},{"ref":"Mark 3:21","short":"Mar 3:21","text":"When his family heard about this, they went to take charge of him, for they said, \u201cHe is out of his mind.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":21},{"ref":"Mark 3:22","short":"Mar 3:22","text":"And the teachers of the law who came down from Jerusalem said, \u201cHe is possessed by Beelzebul! By the prince of demons he is driving out demons.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":22},{"ref":"Mark 3:23","short":"Mar 3:23","text":"So Jesus called them over to him and began to speak to them in parables: \u201cHow can Satan drive out Satan?","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":23},{"ref":"Mark 3:24","short":"Mar 3:24","text":"If a kingdom is divided against itself, that kingdom cannot stand.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":24},{"ref":"Mark 3:25","short":"Mar 3:25","text":"If a house is divided against itself, that house cannot stand.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":25},{"ref":"Mark 3:26","short":"Mar 3:26","text":"And if Satan opposes himself and is divided, he cannot stand; his end has come.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":26},{"ref":"Mark 3:27","short":"Mar 3:27","text":"In fact, no one can enter a strong man\u2019s house without first tying up the strong man. Then he can plunder his house.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":27},{"ref":"Mark 3:28","short":"Mar 3:28","text":"\u201cTruly I tell you, people can be forgiven all their sins and every slander they utter,","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":28},{"ref":"Mark 3:29","short":"Mar 3:29","text":"but whoever blasphemes against the Holy Spirit will never be forgiven; they are guilty of an eternal sin.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":29},{"ref":"Mark 3:30","short":"Mar 3:30","text":"He said this because they were saying, \u201cHe has an impure spirit.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":30},{"ref":"Mark 3:31","short":"Mar 3:31","text":"Then Jesus\u2019 mother and brothers arrived. Standing outside, they sent someone in to call him.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":31},{"ref":"Mark 3:32","short":"Mar 3:32","text":"A crowd was sitting around him, and they told him, \u201cYour mother and brothers are outside looking for you.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":32},{"ref":"Mark 3:33","short":"Mar 3:33","text":"\u201cWho are my mother and my brothers?\u201d he asked.","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":33},{"ref":"Mark 3:34","short":"Mar 3:34","text":"Then he looked at those seated in a circle around him and said, \u201cHere are my mother and my brothers!","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":34},{"ref":"Mark 3:35","short":"Mar 3:35","text":"Whoever does the will of God is my brother and sister and mother.\u201d","url":"nt/mark/Mark_3.html","book":"Mark","ch":3,"v":35},{"ref":"Mark 4:1","short":"Mar 4:1","text":"Again Jesus began to teach by the lake. The crowd that gathered around him was so large that he got into a boat and sat in it out on the lake, while all the people were along the shore at the water\u2019s edge.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":1},{"ref":"Mark 4:2","short":"Mar 4:2","text":"He taught them many things by parables, and in his teaching said:","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":2},{"ref":"Mark 4:3","short":"Mar 4:3","text":"\u201cListen! A farmer went out to sow his seed.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":3},{"ref":"Mark 4:4","short":"Mar 4:4","text":"As he was scattering the seed, some fell along the path, and the birds came and ate it up.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":4},{"ref":"Mark 4:5","short":"Mar 4:5","text":"Some fell on rocky places, where it did not have much soil. It sprang up quickly, because the soil was shallow.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":5},{"ref":"Mark 4:6","short":"Mar 4:6","text":"But when the sun came up, the plants were scorched, and they withered because they had no root.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":6},{"ref":"Mark 4:7","short":"Mar 4:7","text":"Other seed fell among thorns, which grew up and choked the plants, so that they did not bear grain.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":7},{"ref":"Mark 4:8","short":"Mar 4:8","text":"Still other seed fell on good soil. It came up, grew and produced a crop, some multiplying thirty, some sixty, some a hundred times.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":8},{"ref":"Mark 4:9","short":"Mar 4:9","text":"Then Jesus said, \u201cWhoever has ears to hear, let them hear.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":9},{"ref":"Mark 4:10","short":"Mar 4:10","text":"When he was alone, the Twelve and the others around him asked him about the parables.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":10},{"ref":"Mark 4:11","short":"Mar 4:11","text":"He told them, \u201cThe secret of the kingdom of God has been given to you. But to those on the outside everything is said in parables","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":11},{"ref":"Mark 4:12","short":"Mar 4:12","text":"so that, \u201cthey may be ever seeing but never perceiving, and ever hearing but never understanding; otherwise they might turn and be forgiven!\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":12},{"ref":"Mark 4:13","short":"Mar 4:13","text":"\u201cDon\u2019t you understand this parable? How then will you understand any parable?","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":13},{"ref":"Mark 4:14","short":"Mar 4:14","text":"The farmer sows the word.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":14},{"ref":"Mark 4:15","short":"Mar 4:15","text":"Some people are like seed along the path, where the word is sown. As soon as they hear it, Satan comes and takes away the word that was sown in them.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":15},{"ref":"Mark 4:16","short":"Mar 4:16","text":"Others, like seed sown on rocky places, hear the word and at once receive it with joy.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":16},{"ref":"Mark 4:17","short":"Mar 4:17","text":"But since they have no root, they last only a short time. When trouble or persecution comes because of the word, they quickly fall away.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":17},{"ref":"Mark 4:18","short":"Mar 4:18","text":"Still others, like seed sown among thorns, hear the word;","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":18},{"ref":"Mark 4:19","short":"Mar 4:19","text":"but the worries of this life, the deceitfulness of wealth and the desires for other things come in and choke the word, making it unfruitful.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":19},{"ref":"Mark 4:20","short":"Mar 4:20","text":"Others, like seed sown on good soil, hear the word, accept it, and produce a crop\u2014some thirty, some sixty, some a hundred times what was sown.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":20},{"ref":"Mark 4:21","short":"Mar 4:21","text":"He said to them, \u201cDo you bring in a lamp to put it under a bowl or a bed? Instead, don\u2019t you put it on its stand?","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":21},{"ref":"Mark 4:22","short":"Mar 4:22","text":"For whatever is hidden is meant to be disclosed, and whatever is concealed is meant to be brought out into the open.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":22},{"ref":"Mark 4:23","short":"Mar 4:23","text":"If anyone has ears to hear, let them hear.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":23},{"ref":"Mark 4:24","short":"Mar 4:24","text":"\u201cConsider carefully what you hear,\u201d he continued. \u201cWith the measure you use, it will be measured to you\u2014and even more.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":24},{"ref":"Mark 4:25","short":"Mar 4:25","text":"Whoever has will be given more; whoever does not have, even what they have will be taken from them.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":25},{"ref":"Mark 4:26","short":"Mar 4:26","text":"He also said, \u201cThis is what the kingdom of God is like. A man scatters seed on the ground.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":26},{"ref":"Mark 4:27","short":"Mar 4:27","text":"Night and day, whether he sleeps or gets up, the seed sprouts and grows, though he does not know how.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":27},{"ref":"Mark 4:28","short":"Mar 4:28","text":"All by itself the soil produces grain\u2014first the stalk, then the head, then the full kernel in the head.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":28},{"ref":"Mark 4:29","short":"Mar 4:29","text":"As soon as the grain is ripe, he puts the sickle to it, because the harvest has come.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":29},{"ref":"Mark 4:30","short":"Mar 4:30","text":"Again he said, \u201cWhat shall we say the kingdom of God is like, or what parable shall we use to describe it?","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":30},{"ref":"Mark 4:31","short":"Mar 4:31","text":"It is like a mustard seed, which is the smallest of all seeds on earth.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":31},{"ref":"Mark 4:32","short":"Mar 4:32","text":"Yet when planted, it grows and becomes the largest of all garden plants, with such big branches that the birds can perch in its shade.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":32},{"ref":"Mark 4:33","short":"Mar 4:33","text":"With many similar parables Jesus spoke the word to them, as much as they could understand.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":33},{"ref":"Mark 4:34","short":"Mar 4:34","text":"He did not say anything to them without using a parable. But when he was alone with his own disciples, he explained everything.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":34},{"ref":"Mark 4:35","short":"Mar 4:35","text":"That day when evening came, he said to his disciples, \u201cLet us go over to the other side.\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":35},{"ref":"Mark 4:36","short":"Mar 4:36","text":"Leaving the crowd behind, they took him along, just as he was, in the boat. There were also other boats with him.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":36},{"ref":"Mark 4:37","short":"Mar 4:37","text":"A furious squall came up, and the waves broke over the boat, so that it was nearly swamped.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":37},{"ref":"Mark 4:38","short":"Mar 4:38","text":"Jesus was in the stern, sleeping on a cushion. The disciples woke him and said to him, \u201cTeacher, don\u2019t you care if we drown?\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":38},{"ref":"Mark 4:39","short":"Mar 4:39","text":"He got up, rebuked the wind and said to the waves, \u201cQuiet! Be still!\u201d The wind died down and it was completely calm.","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":39},{"ref":"Mark 4:40","short":"Mar 4:40","text":"He said to his disciples, \u201cWhy are you so afraid? Do you still have no faith?\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":40},{"ref":"Mark 4:41","short":"Mar 4:41","text":"They were terrified and asked each other, \u201cWho is this? Even the wind and the waves obey him!\u201d","url":"nt/mark/Mark_4.html","book":"Mark","ch":4,"v":41},{"ref":"Mark 5:1","short":"Mar 5:1","text":"They went across the lake to the region of the Gerasenes.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":1},{"ref":"Mark 5:2","short":"Mar 5:2","text":"When Jesus got out of the boat, a man with an impure spirit came from the tombs to meet him.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":2},{"ref":"Mark 5:3","short":"Mar 5:3","text":"This man lived in the tombs, and no one could bind him anymore, not even with a chain.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":3},{"ref":"Mark 5:4","short":"Mar 5:4","text":"For he had often been chained hand and foot, but he tore the chains apart and broke the irons on his feet. No one was strong enough to subdue him.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":4},{"ref":"Mark 5:5","short":"Mar 5:5","text":"Night and day among the tombs and in the hills he would cry out and cut himself with stones.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":5},{"ref":"Mark 5:6","short":"Mar 5:6","text":"When he saw Jesus from a distance, he ran and fell on his knees in front of him.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":6},{"ref":"Mark 5:7","short":"Mar 5:7","text":"He shouted at the top of his voice, \u201cWhat do you want with me, Jesus, Son of the Most High God? In God\u2019s name don\u2019t torture me!\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":7},{"ref":"Mark 5:8","short":"Mar 5:8","text":"For Jesus had said to him, \u201cCome out of this man, you impure spirit!\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":8},{"ref":"Mark 5:9","short":"Mar 5:9","text":"Then Jesus asked him, \u201cWhat is your name?\u201d \u201cMy name is Legion,\u201d he replied, \u201cfor we are many.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":9},{"ref":"Mark 5:10","short":"Mar 5:10","text":"And he begged Jesus again and again not to send them out of the area.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":10},{"ref":"Mark 5:11","short":"Mar 5:11","text":"A large herd of pigs was feeding on the nearby hillside.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":11},{"ref":"Mark 5:12","short":"Mar 5:12","text":"The demons begged Jesus, \u201cSend us among the pigs; allow us to go into them.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":12},{"ref":"Mark 5:13","short":"Mar 5:13","text":"He gave them permission, and the impure spirits came out and went into the pigs. The herd, about two thousand in number, rushed down the steep bank into the lake and were drowned.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":13},{"ref":"Mark 5:14","short":"Mar 5:14","text":"Those tending the pigs ran off and reported this in the town and countryside, and the people went out to see what had happened.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":14},{"ref":"Mark 5:15","short":"Mar 5:15","text":"When they came to Jesus, they saw the man who had been possessed by the legion of demons, sitting there, dressed and in his right mind; and they were afraid.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":15},{"ref":"Mark 5:16","short":"Mar 5:16","text":"Those who had seen it told the people what had happened to the demon-possessed man\u2014and told about the pigs as well.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":16},{"ref":"Mark 5:17","short":"Mar 5:17","text":"Then the people began to plead with Jesus to leave their region.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":17},{"ref":"Mark 5:18","short":"Mar 5:18","text":"As Jesus was getting into the boat, the man who had been demon-possessed begged to go with him.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":18},{"ref":"Mark 5:19","short":"Mar 5:19","text":"Jesus did not let him, but said, \u201cGo home to your own people and tell them how much the Lord has done for you, and how he has had mercy on you.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":19},{"ref":"Mark 5:20","short":"Mar 5:20","text":"So the man went away and began to tell in the Decapolis how much Jesus had done for him. And all the people were amazed.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":20},{"ref":"Mark 5:21","short":"Mar 5:21","text":"When Jesus had again crossed over by boat to the other side of the lake, a large crowd gathered around him while he was by the lake.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":21},{"ref":"Mark 5:22","short":"Mar 5:22","text":"Then one of the synagogue leaders, named Jairus, came, and when he saw Jesus, he fell at his feet.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":22},{"ref":"Mark 5:23","short":"Mar 5:23","text":"He pleaded earnestly with him, \u201cMy little daughter is dying. Please come and put your hands on her so that she will be healed and live.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":23},{"ref":"Mark 5:24","short":"Mar 5:24","text":"So Jesus went with him. A large crowd followed and pressed around him.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":24},{"ref":"Mark 5:25","short":"Mar 5:25","text":"And a woman was there who had been subject to bleeding for twelve years.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":25},{"ref":"Mark 5:26","short":"Mar 5:26","text":"She had suffered a great deal under the care of many doctors and had spent all she had, yet instead of getting better she grew worse.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":26},{"ref":"Mark 5:27","short":"Mar 5:27","text":"When she heard about Jesus, she came up behind him in the crowd and touched his cloak,","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":27},{"ref":"Mark 5:28","short":"Mar 5:28","text":"because she thought, \u201cIf I just touch his clothes, I will be healed.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":28},{"ref":"Mark 5:29","short":"Mar 5:29","text":"Immediately her bleeding stopped and she felt in her body that she was freed from her suffering.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":29},{"ref":"Mark 5:30","short":"Mar 5:30","text":"At once Jesus realized that power had gone out from him. He turned around in the crowd and asked, \u201cWho touched my clothes?\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":30},{"ref":"Mark 5:31","short":"Mar 5:31","text":"You see the people crowding against you,\u201d his disciples answered, \u201cand yet you can ask, \u201cWho touched me?\u201d\u2019","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":31},{"ref":"Mark 5:32","short":"Mar 5:32","text":"But Jesus kept looking around to see who had done it.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":32},{"ref":"Mark 5:33","short":"Mar 5:33","text":"Then the woman, knowing what had happened to her, came and fell at his feet and, trembling with fear, told him the whole truth.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":33},{"ref":"Mark 5:34","short":"Mar 5:34","text":"He said to her, \u201cDaughter, your faith has healed you. Go in peace and be freed from your suffering.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":34},{"ref":"Mark 5:35","short":"Mar 5:35","text":"While Jesus was still speaking, some people came from the house of Jairus, the synagogue leader. \u201cYour daughter is dead,\u201d they said. \u201cWhy bother the teacher anymore?\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":35},{"ref":"Mark 5:36","short":"Mar 5:36","text":"Overhearing what they said, Jesus told the synagogue leader, \u201cDon\u2019t be afraid; just believe.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":36},{"ref":"Mark 5:37","short":"Mar 5:37","text":"He did not let anyone follow him except Peter, James and John the brother of James.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":37},{"ref":"Mark 5:38","short":"Mar 5:38","text":"When they came to the home of the synagogue leader, Jesus saw a commotion, with people crying and wailing loudly.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":38},{"ref":"Mark 5:39","short":"Mar 5:39","text":"He went in and said to them, \u201cWhy all this commotion and wailing? The child is not dead but asleep.\u201d","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":39},{"ref":"Mark 5:40","short":"Mar 5:40","text":"But they laughed at him. After he put them all out, he took the child\u2019s father and mother and the disciples who were with him, and went in where the child was.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":40},{"ref":"Mark 5:41","short":"Mar 5:41","text":"He took her by the hand and said to her, \u201cTalitha koum!\u201d (which means \u201cLittle girl, I say to you, get up!\u201d).","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":41},{"ref":"Mark 5:42","short":"Mar 5:42","text":"Immediately the girl stood up and began to walk around (she was twelve years old). At this they were completely astonished.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":42},{"ref":"Mark 5:43","short":"Mar 5:43","text":"He gave strict orders not to let anyone know about this, and told them to give her something to eat.","url":"nt/mark/Mark_5.html","book":"Mark","ch":5,"v":43},{"ref":"Mark 6:1","short":"Mar 6:1","text":"Jesus left there and went to his hometown, accompanied by his disciples.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":1},{"ref":"Mark 6:2","short":"Mar 6:2","text":"When the Sabbath came, he began to teach in the synagogue, and many who heard him were amazed. \u201cWhere did this man get these things?\u201d they asked. \u201cWhat\u2019s this wisdom that has been given him? What are these remarkable miracles he is performing?","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":2},{"ref":"Mark 6:3","short":"Mar 6:3","text":"Isn\u2019t this the carpenter? Isn\u2019t this Mary\u2019s son and the brother of James, Joseph, Judas and Simon? Aren\u2019t his sisters here with us?\u201d And they took offense at him.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":3},{"ref":"Mark 6:4","short":"Mar 6:4","text":"Jesus said to them, \u201cA prophet is not accepted in his hometown, among his relatives and in his own home.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":4},{"ref":"Mark 6:5","short":"Mar 6:5","text":"He could not do any miracles there, except lay his hands on a few sick people and heal them.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":5},{"ref":"Mark 6:6","short":"Mar 6:6","text":"He was amazed at their lack of faith. Then Jesus went around teaching from village to village.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":6},{"ref":"Mark 6:7","short":"Mar 6:7","text":"Calling the Twelve to him, he began to send them out two by two and gave them authority over impure spirits.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":7},{"ref":"Mark 6:8","short":"Mar 6:8","text":"\u201cTake nothing for the journey except a staff\u2014no bag, no bread, no money, no extra shirt.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":8},{"ref":"Mark 6:9","short":"Mar 6:9","text":"Wear sandals but not an extra tunic.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":9},{"ref":"Mark 6:10","short":"Mar 6:10","text":"\u201cWhenever you enter a house, stay there until you leave that town.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":10},{"ref":"Mark 6:11","short":"Mar 6:11","text":"And if any place will not welcome you or listen to you, leave that place and shake the dust off your feet as a testimony against them.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":11},{"ref":"Mark 6:12","short":"Mar 6:12","text":"They went out and preached that people should repent.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":12},{"ref":"Mark 6:13","short":"Mar 6:13","text":"They drove out many demons and anointed many sick people with oil and healed them.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":13},{"ref":"Mark 6:14","short":"Mar 6:14","text":"King Herod heard about this, for Jesus\u2019 name had become well known. Some were saying, \u201cJohn the Baptist has been raised from the dead, and that is why miraculous powers are at work in him.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":14},{"ref":"Mark 6:15","short":"Mar 6:15","text":"Others said, \u201cHe is Elijah.\u201d And still others claimed, \u201cHe is a prophet, like one of the prophets of long ago.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":15},{"ref":"Mark 6:16","short":"Mar 6:16","text":"But when Herod heard this, he said, \u201cJohn, whom I beheaded, has been raised from the dead!\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":16},{"ref":"Mark 6:17","short":"Mar 6:17","text":"For Herod himself had given orders to have John arrested, and he had him bound and put in prison. He did this because of Herodias, his brother Philip\u2019s wife, whom he had married.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":17},{"ref":"Mark 6:18","short":"Mar 6:18","text":"For John had been saying to Herod, \u201cIt is not lawful for you to have your brother\u2019s wife.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":18},{"ref":"Mark 6:19","short":"Mar 6:19","text":"So Herodias nursed a grudge against John and wanted to kill him. But she was not able to,","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":19},{"ref":"Mark 6:20","short":"Mar 6:20","text":"because Herod feared John and protected him, knowing him to be a righteous and holy man. When Herod heard John, he was greatly puzzled; yet he liked to listen to him.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":20},{"ref":"Mark 6:21","short":"Mar 6:21","text":"Finally the opportune time came. On his birthday Herod gave a banquet for his high officials and military commanders and the leading men of Galilee.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":21},{"ref":"Mark 6:22","short":"Mar 6:22","text":"When the daughter of Herodias came in and danced, she pleased Herod and his dinner guests. The king said to the girl, \u201cAsk me for anything you want, and I\u2019ll give it to you.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":22},{"ref":"Mark 6:23","short":"Mar 6:23","text":"And he promised her with an oath: \u201cWhatever you ask I will give you, up to half my kingdom.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":23},{"ref":"Mark 6:24","short":"Mar 6:24","text":"She went out and said to her mother, \u201cWhat shall I ask for?\u201d \u201cThe head of John the Baptist,\u201d she answered.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":24},{"ref":"Mark 6:25","short":"Mar 6:25","text":"At once she hurried in to the king with the request: \u201cI want you to give me right now the head of John the Baptist on a platter.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":25},{"ref":"Mark 6:26","short":"Mar 6:26","text":"The king was greatly distressed, but because of his oaths and his dinner guests, he did not want to refuse her.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":26},{"ref":"Mark 6:27","short":"Mar 6:27","text":"So he immediately sent an executioner with orders to bring John\u2019s head. The man went, beheaded John in the prison,","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":27},{"ref":"Mark 6:28","short":"Mar 6:28","text":"and brought back his head on a platter. He presented it to the girl, and she gave it to her mother.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":28},{"ref":"Mark 6:29","short":"Mar 6:29","text":"On hearing of this, John\u2019s disciples came and took his body and laid it in a tomb.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":29},{"ref":"Mark 6:30","short":"Mar 6:30","text":"The apostles gathered around Jesus and reported to him all they had done and taught.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":30},{"ref":"Mark 6:31","short":"Mar 6:31","text":"Then, because so many people were coming and going that they did not even have a chance to eat, he said to them, \u201cCome with me by yourselves to a quiet place and get some rest.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":31},{"ref":"Mark 6:32","short":"Mar 6:32","text":"So they went away by themselves in a boat to a solitary place.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":32},{"ref":"Mark 6:33","short":"Mar 6:33","text":"But many who saw them leaving recognized them and ran on foot from all the towns and got there ahead of them.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":33},{"ref":"Mark 6:34","short":"Mar 6:34","text":"When Jesus landed and saw a large crowd, he had compassion on them, because they were like sheep without a shepherd. He began teaching them many things.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":34},{"ref":"Mark 6:35","short":"Mar 6:35","text":"By this time it was late in the day, so his disciples came to him. \u201cThis is a remote place,\u201d they said, \u201cand it\u2019s already very late.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":35},{"ref":"Mark 6:36","short":"Mar 6:36","text":"Send the people away so they can go to the surrounding countryside and villages and buy themselves something to eat.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":36},{"ref":"Mark 6:37","short":"Mar 6:37","text":"But he answered, \u201cYou give them something to eat.\u201d They said to him, \u201cThat would take more than half a year\u2019s wages! Are we to go and spend that much on bread and give it to them to eat?\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":37},{"ref":"Mark 6:38","short":"Mar 6:38","text":"How many loaves do you have?\u201d he asked. \u201cGo and see.\u201d When they found out, they said, \u201cFive\u2014and two fish.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":38},{"ref":"Mark 6:39","short":"Mar 6:39","text":"Then Jesus directed them to have all the people sit down in groups on the green grass.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":39},{"ref":"Mark 6:40","short":"Mar 6:40","text":"So they sat down in groups of hundreds and fifties.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":40},{"ref":"Mark 6:41","short":"Mar 6:41","text":"Taking the five loaves and the two fish and looking up to heaven, he gave thanks and broke the loaves. Then he gave them to his disciples to distribute to the people. He also divided the two fish among them all.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":41},{"ref":"Mark 6:42","short":"Mar 6:42","text":"They all ate and were satisfied,","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":42},{"ref":"Mark 6:43","short":"Mar 6:43","text":"and the disciples picked up twelve basketfuls of broken pieces of bread and fish.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":43},{"ref":"Mark 6:44","short":"Mar 6:44","text":"The number of those who had eaten was five thousand men.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":44},{"ref":"Mark 6:45","short":"Mar 6:45","text":"Immediately Jesus made his disciples get into the boat and go on ahead of him to Bethsaida, while he dismissed the crowd.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":45},{"ref":"Mark 6:46","short":"Mar 6:46","text":"After leaving them, he went up on a mountainside to pray.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":46},{"ref":"Mark 6:47","short":"Mar 6:47","text":"Later that night, the boat was in the middle of the lake, and he was alone on land.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":47},{"ref":"Mark 6:48","short":"Mar 6:48","text":"He saw the disciples straining at the oars, because the wind was against them. Shortly before dawn he went out to them, walking on the lake. He was about to pass by them,","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":48},{"ref":"Mark 6:49","short":"Mar 6:49","text":"but when they saw him walking on the lake, they thought he was a ghost. They cried out,","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":49},{"ref":"Mark 6:50","short":"Mar 6:50","text":"because they all saw him and were terrified. Immediately he spoke to them and said, \u201cTake courage! It is I. Don\u2019t be afraid.\u201d","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":50},{"ref":"Mark 6:51","short":"Mar 6:51","text":"Then he climbed into the boat with them, and the wind died down. They were completely amazed, for they had not understood about the loaves; their hearts were hardened.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":51},{"ref":"Mark 6:52","short":"Mar 6:52","text":"They were completely amazed, for they had not understood about the loaves; their hearts were hardened.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":52},{"ref":"Mark 6:53","short":"Mar 6:53","text":"When they had crossed over, they landed at Gennesaret and anchored there.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":53},{"ref":"Mark 6:54","short":"Mar 6:54","text":"As soon as they got out of the boat, people recognized Jesus.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":54},{"ref":"Mark 6:55","short":"Mar 6:55","text":"They ran throughout that whole region and carried the sick on mats to wherever they heard he was.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":55},{"ref":"Mark 6:56","short":"Mar 6:56","text":"And wherever he went\u2014into villages, towns or countryside\u2014they placed the sick in the marketplaces. They begged him to let them touch even the edge of his cloak, and all who touched it were healed.","url":"nt/mark/Mark_6.html","book":"Mark","ch":6,"v":56},{"ref":"Mark 7:1","short":"Mar 7:1","text":"The Pharisees and some teachers of the law who had come from Jerusalem gathered around Jesus.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":1},{"ref":"Mark 7:2","short":"Mar 7:2","text":"They saw some of his disciples eating food with hands that were defiled, that is, unwashed.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":2},{"ref":"Mark 7:3","short":"Mar 7:3","text":"(The Pharisees and all the Jews do not eat unless they give their hands a ritual washing, holding to the tradition of the elders.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":3},{"ref":"Mark 7:4","short":"Mar 7:4","text":"When they come from the marketplace they do not eat unless they wash. And they observe many other traditions, such as the washing of cups, pitchers and kettles.)","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":4},{"ref":"Mark 7:5","short":"Mar 7:5","text":"So the Pharisees and teachers of the law asked Jesus, \u201cWhy don\u2019t your disciples live according to the tradition of the elders instead of eating their food with defiled hands?\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":5},{"ref":"Mark 7:6","short":"Mar 7:6","text":"He replied, \u201cIsaiah was right when he prophesied about you hypocrites; as it is written: \u201c\u2018These people honor me with their lips, but their hearts are far from me.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":6},{"ref":"Mark 7:7","short":"Mar 7:7","text":"They worship me in vain; their teachings are merely human rules.\u2019","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":7},{"ref":"Mark 7:8","short":"Mar 7:8","text":"You have let go of the commands of God and are holding on to human traditions.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":8},{"ref":"Mark 7:9","short":"Mar 7:9","text":"And he continued, \u201cYou have a fine way of setting aside the commands of God in order to observe your own traditions!","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":9},{"ref":"Mark 7:10","short":"Mar 7:10","text":"For Moses said, \u201cHonor your father and your mother,\u201d and, \u201cAnyone who curses their father or mother is to be put to death.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":10},{"ref":"Mark 7:11","short":"Mar 7:11","text":"But you say that if anyone declares that what might have been used to help their father or mother is Corban (that is, devoted to God)\u2014","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":11},{"ref":"Mark 7:12","short":"Mar 7:12","text":"then you no longer let them do anything for their father or mother.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":12},{"ref":"Mark 7:13","short":"Mar 7:13","text":"Thus you nullify the word of God by your tradition that you have handed down. And you do many things like that.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":13},{"ref":"Mark 7:14","short":"Mar 7:14","text":"Again Jesus called the crowd to him and said, \u201cListen to me, everyone, and understand this.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":14},{"ref":"Mark 7:15","short":"Mar 7:15","text":"Nothing outside a person can defile them by going into them. Rather, it is what comes out of a person that defiles them.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":15},{"ref":"Mark 7:17","short":"Mar 7:17","text":"After he had left the crowd and entered the house, his disciples asked him about this parable.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":17},{"ref":"Mark 7:18","short":"Mar 7:18","text":"Are you so dull?\u201d he asked. \u201cDon\u2019t you see that nothing that enters a person from the outside can defile them?","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":18},{"ref":"Mark 7:19","short":"Mar 7:19","text":"For it doesn\u2019t go into their heart but into their stomach, and then out of the body.\u201d (In saying this, Jesus declared all foods clean.)","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":19},{"ref":"Mark 7:20","short":"Mar 7:20","text":"He went on: \u201cWhat comes out of a person is what defiles them.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":20},{"ref":"Mark 7:21","short":"Mar 7:21","text":"For it is from within, out of a person\u2019s heart, that evil thoughts come\u2014sexual immorality, theft, murder,","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":21},{"ref":"Mark 7:22","short":"Mar 7:22","text":"adultery, greed, malice, deceit, lewdness, envy, slander, arrogance and folly.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":22},{"ref":"Mark 7:23","short":"Mar 7:23","text":"All these evils come from inside and defile a person.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":23},{"ref":"Mark 7:24","short":"Mar 7:24","text":"Jesus left that place and went to the vicinity of Tyre. He entered a house and did not want anyone to know it; yet he could not keep his presence secret.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":24},{"ref":"Mark 7:25","short":"Mar 7:25","text":"In fact, as soon as she heard about him, a woman whose little daughter was possessed by an impure spirit came and fell at his feet.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":25},{"ref":"Mark 7:26","short":"Mar 7:26","text":"The woman was a Greek, born in Syrian Phoenicia. She begged Jesus to drive the demon out of her daughter.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":26},{"ref":"Mark 7:27","short":"Mar 7:27","text":"First let the children eat all they want,\u201d he told her, \u201cfor it is not right to take the children\u2019s bread and toss it to the dogs.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":27},{"ref":"Mark 7:28","short":"Mar 7:28","text":"Lord,\u201d she replied, \u201ceven the dogs under the table eat the children\u2019s crumbs.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":28},{"ref":"Mark 7:29","short":"Mar 7:29","text":"Then he told her, \u201cFor such a reply, you may go; the demon has left your daughter.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":29},{"ref":"Mark 7:30","short":"Mar 7:30","text":"She went home and found her child lying on the bed, and the demon gone.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":30},{"ref":"Mark 7:31","short":"Mar 7:31","text":"Then Jesus left the vicinity of Tyre and went through Sidon, down to the Sea of Galilee and into the region of the Decapolis.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":31},{"ref":"Mark 7:32","short":"Mar 7:32","text":"There some people brought to him a man who was deaf and could hardly talk, and they begged Jesus to place his hand on him.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":32},{"ref":"Mark 7:33","short":"Mar 7:33","text":"After he took him aside, away from the crowd, Jesus put his fingers into the man\u2019s ears. Then he spit and touched the man\u2019s tongue.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":33},{"ref":"Mark 7:34","short":"Mar 7:34","text":"He looked up to heaven and with a deep sigh said to him, \u201cEphatha!\u201d (which means \u201cBe opened!\u201d).","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":34},{"ref":"Mark 7:35","short":"Mar 7:35","text":"At this, the man\u2019s ears were opened, his tongue was loosened and he began to speak plainly.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":35},{"ref":"Mark 7:36","short":"Mar 7:36","text":"Jesus commanded them not to tell anyone. But the more he did so, the more they kept talking about it.","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":36},{"ref":"Mark 7:37","short":"Mar 7:37","text":"People were overwhelmed with amazement. \u201cHe has done everything well,\u201d they said. \u201cHe even makes the deaf hear and the mute speak.\u201d","url":"nt/mark/Mark_7.html","book":"Mark","ch":7,"v":37},{"ref":"Mark 8:1","short":"Mar 8:1","text":"During those days another large crowd gathered. Since they had nothing to eat, Jesus called his disciples to him and said,","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":1},{"ref":"Mark 8:2","short":"Mar 8:2","text":"\u201cI have compassion for these people; they have already been with me three days and have nothing to eat.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":2},{"ref":"Mark 8:3","short":"Mar 8:3","text":"If I send them home hungry, they will collapse on the way, because some of them have come a long distance.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":3},{"ref":"Mark 8:4","short":"Mar 8:4","text":"His disciples answered, \u201cBut where in this remote place can anyone get enough bread to feed them?\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":4},{"ref":"Mark 8:5","short":"Mar 8:5","text":"\u201cHow many loaves do you have?\u201d Jesus asked. \u201cSeven,\u201d they replied.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":5},{"ref":"Mark 8:6","short":"Mar 8:6","text":"He told the crowd to sit down on the ground. When he had taken the seven loaves and given thanks, he broke them and gave them to his disciples to distribute to the people, and they did so.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":6},{"ref":"Mark 8:7","short":"Mar 8:7","text":"They had a few small fish as well; he gave thanks for them also and told the disciples to distribute them.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":7},{"ref":"Mark 8:8","short":"Mar 8:8","text":"The people ate and were satisfied. Afterward the disciples picked up seven basketfuls of broken pieces that were left over.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":8},{"ref":"Mark 8:9","short":"Mar 8:9","text":"About four thousand were present. After he had sent them away,","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":9},{"ref":"Mark 8:10","short":"Mar 8:10","text":"he got into the boat with his disciples and went to the region of Dalmanutha.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":10},{"ref":"Mark 8:11","short":"Mar 8:11","text":"The Pharisees came and began to question Jesus. To test him, they asked him for a sign from heaven.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":11},{"ref":"Mark 8:12","short":"Mar 8:12","text":"He sighed deeply and said, \u201cWhy does this generation ask for a sign? Truly I tell you, no sign will be given to it.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":12},{"ref":"Mark 8:13","short":"Mar 8:13","text":"Then he left them, got back into the boat and crossed to the other side.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":13},{"ref":"Mark 8:14","short":"Mar 8:14","text":"The disciples had forgotten to bring bread, except for one loaf they had with them in the boat.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":14},{"ref":"Mark 8:15","short":"Mar 8:15","text":"\u201cBe careful,\u201d Jesus warned them. \u201cWatch out for the yeast of the Pharisees and that of Herod.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":15},{"ref":"Mark 8:16","short":"Mar 8:16","text":"They discussed this with one another and said, \u201cIt is because we have no bread.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":16},{"ref":"Mark 8:17","short":"Mar 8:17","text":"Aware of their discussion, Jesus asked them: \u201cWhy are you talking about having no bread? Do you still not see or understand? Are your hearts hardened?","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":17},{"ref":"Mark 8:18","short":"Mar 8:18","text":"Do you have eyes but fail to see, and ears but fail to hear? And don\u2019t you remember?","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":18},{"ref":"Mark 8:19","short":"Mar 8:19","text":"When I broke the five loaves for the five thousand, how many basketfuls of pieces did you pick up?\u201d \u201cTwelve,\u201d they replied.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":19},{"ref":"Mark 8:20","short":"Mar 8:20","text":"\u201cAnd when I broke the seven loaves for the four thousand, how many basketfuls of pieces did you pick up?\u201d They answered, \u201cSeven.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":20},{"ref":"Mark 8:21","short":"Mar 8:21","text":"He said to them, \u201cDo you still not understand?\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":21},{"ref":"Mark 8:22","short":"Mar 8:22","text":"They came to Bethsaida, and some people brought a blind man and begged Jesus to touch him.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":22},{"ref":"Mark 8:23","short":"Mar 8:23","text":"He took the blind man by the hand and led him outside the village. When he had spit on the man\u2019s eyes and put his hands on him, Jesus asked, \u201cDo you see anything?\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":23},{"ref":"Mark 8:24","short":"Mar 8:24","text":"\u201cI see people; they look like trees walking around,\u201d he said.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":24},{"ref":"Mark 8:25","short":"Mar 8:25","text":"Once more Jesus put his hands on the man\u2019s eyes. Then his eyes were opened, his sight was restored, and he saw everything clearly.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":25},{"ref":"Mark 8:26","short":"Mar 8:26","text":"Jesus sent him home, saying, \u201cDon\u2019t even go into the village.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":26},{"ref":"Mark 8:27","short":"Mar 8:27","text":"Jesus and his disciples went on to the villages around Caesarea Philippi. On the way he asked them, \u201cWho do people say I am?\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":27},{"ref":"Mark 8:28","short":"Mar 8:28","text":"They replied, \u201cSome say John the Baptist; others say Elijah; and still others, one of the prophets.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":28},{"ref":"Mark 8:29","short":"Mar 8:29","text":"\u201cBut what about you?\u201d he asked. \u201cWho do you say I am?\u201d Peter answered, \u201cYou are the Messiah.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":29},{"ref":"Mark 8:30","short":"Mar 8:30","text":"Jesus warned them not to tell anyone about him.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":30},{"ref":"Mark 8:31","short":"Mar 8:31","text":"He then began to teach them that the Son of Man must suffer many things and be rejected by the elders, the chief priests and the teachers of the law, and that he must be killed and after three days rise again.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":31},{"ref":"Mark 8:32","short":"Mar 8:32","text":"He spoke plainly about this, and Peter took him aside and began to rebuke him.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":32},{"ref":"Mark 8:33","short":"Mar 8:33","text":"But when Jesus turned and looked at his disciples, he rebuked Peter. \u201cGet behind me, Satan!\u201d he said. \u201cYou do not have in mind the concerns of God, but merely human concerns.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":33},{"ref":"Mark 8:34","short":"Mar 8:34","text":"Then he called the crowd to him along with his disciples and said: \u201cWhoever wants to be my disciple must deny themselves and take up their cross and follow me.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":34},{"ref":"Mark 8:35","short":"Mar 8:35","text":"For whoever wants to save their life will lose it, but whoever loses their life for me and for the gospel will save it.","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":35},{"ref":"Mark 8:36","short":"Mar 8:36","text":"What good is it for someone to gain the whole world, yet forfeit their soul?","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":36},{"ref":"Mark 8:37","short":"Mar 8:37","text":"Or what can anyone give in exchange for their soul?","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":37},{"ref":"Mark 8:38","short":"Mar 8:38","text":"If anyone is ashamed of me and my words in this adulterous and sinful generation, the Son of Man will be ashamed of them when he comes in his Father\u2019s glory with the holy angels.\u201d","url":"nt/mark/Mark_8.html","book":"Mark","ch":8,"v":38},{"ref":"Mark 9:1","short":"Mar 9:1","text":"And he said to them, \u201cTruly I tell you, some who are standing here will not taste death before they see that the kingdom of God has come with power.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":1},{"ref":"Mark 9:2","short":"Mar 9:2","text":"After six days Jesus took Peter, James and John with him and led them up a high mountain, where they were all alone. There he was transfigured before them.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":2},{"ref":"Mark 9:3","short":"Mar 9:3","text":"His clothes became dazzling white, whiter than anyone in the world could bleach them.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":3},{"ref":"Mark 9:4","short":"Mar 9:4","text":"And there appeared before them Elijah and Moses, who were talking with Jesus.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":4},{"ref":"Mark 9:5","short":"Mar 9:5","text":"Peter said to Jesus, \u201cRabbi, it is good for us to be here. Let us put up three shelters\u2014one for you, one for Moses and one for Elijah.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":5},{"ref":"Mark 9:6","short":"Mar 9:6","text":"(He did not know what to say, they were so frightened.)","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":6},{"ref":"Mark 9:7","short":"Mar 9:7","text":"Then a cloud appeared and covered them, and a voice came from the cloud: \u201cThis is my Son, whom I love. Listen to him!\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":7},{"ref":"Mark 9:8","short":"Mar 9:8","text":"Suddenly, when they looked around, they no longer saw anyone with them except Jesus.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":8},{"ref":"Mark 9:9","short":"Mar 9:9","text":"As they were coming down the mountain, Jesus gave them orders not to tell anyone what they had seen until the Son of Man had risen from the dead.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":9},{"ref":"Mark 9:10","short":"Mar 9:10","text":"They kept the matter to themselves, discussing what \u201crising from the dead\u201d meant.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":10},{"ref":"Mark 9:11","short":"Mar 9:11","text":"And they asked him, \u201cWhy do the teachers of the law say that Elijah must come first?\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":11},{"ref":"Mark 9:12","short":"Mar 9:12","text":"\u201cTo be sure, Elijah does come first, and restores all things. Why then is it written that the Son of Man must suffer much and be rejected?","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":12},{"ref":"Mark 9:13","short":"Mar 9:13","text":"But I tell you, Elijah has come, and they have done to him everything they wished, just as it is written about him.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":13},{"ref":"Mark 9:14","short":"Mar 9:14","text":"When they came to the other disciples, they saw a large crowd around them and the teachers of the law arguing with them.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":14},{"ref":"Mark 9:15","short":"Mar 9:15","text":"As soon as all the people saw Jesus, they were overwhelmed with wonder and ran to greet him.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":15},{"ref":"Mark 9:16","short":"Mar 9:16","text":"\u201cWhat are you arguing with them about?\u201d he asked.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":16},{"ref":"Mark 9:17","short":"Mar 9:17","text":"A man in the crowd answered, \u201cTeacher, I brought you my son, who is possessed by a spirit that has robbed him of speech.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":17},{"ref":"Mark 9:18","short":"Mar 9:18","text":"Whenever it seizes him, it throws him to the ground. He foams at the mouth, gnashes his teeth and becomes rigid. I asked your disciples to drive out the spirit, but they could not.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":18},{"ref":"Mark 9:19","short":"Mar 9:19","text":"\u201cYou unbelieving generation,\u201d Jesus replied, \u201chow long shall I stay with you? How long shall I put up with you? Bring the boy to me.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":19},{"ref":"Mark 9:20","short":"Mar 9:20","text":"So they brought him. When the spirit saw Jesus, it immediately threw the boy into a convulsion. He fell to the ground and rolled around, foaming at the mouth.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":20},{"ref":"Mark 9:21","short":"Mar 9:21","text":"Jesus asked the boy\u2019s father, \u201cHow long has he been like this?\u201d \u201cFrom childhood,\u201d he answered.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":21},{"ref":"Mark 9:22","short":"Mar 9:22","text":"\u201cIt has often thrown him into fire or water to kill him. But if you can do anything, take pity on us and help us.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":22},{"ref":"Mark 9:23","short":"Mar 9:23","text":"\u201cIf you can?\u201d said Jesus. \u201cEverything is possible for one who believes.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":23},{"ref":"Mark 9:24","short":"Mar 9:24","text":"Immediately the boy\u2019s father exclaimed, \u201cI do believe; help me overcome my unbelief!\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":24},{"ref":"Mark 9:25","short":"Mar 9:25","text":"When Jesus saw that a crowd was running to the scene, he rebuked the impure spirit. \u201cYou deaf and mute spirit,\u201d he said, \u201cI command you, come out of him and never enter him again.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":25},{"ref":"Mark 9:26","short":"Mar 9:26","text":"The spirit shrieked, convulsed him violently and came out. The boy looked so much like a corpse that many said, \u201cHe\u2019s dead.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":26},{"ref":"Mark 9:27","short":"Mar 9:27","text":"But Jesus took him by the hand and lifted him to his feet, and he stood up.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":27},{"ref":"Mark 9:28","short":"Mar 9:28","text":"After Jesus had gone indoors, his disciples asked him privately, \u201cWhy couldn\u2019t we drive it out?\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":28},{"ref":"Mark 9:29","short":"Mar 9:29","text":"He replied, \u201cThis kind can come out only by prayer.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":29},{"ref":"Mark 9:30","short":"Mar 9:30","text":"They left that place and passed through Galilee. Jesus did not want anyone to know where they were,","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":30},{"ref":"Mark 9:31","short":"Mar 9:31","text":"because he was teaching his disciples. He said to them, \u201cThe Son of Man is going to be delivered into the hands of men. They will kill him, and after three days he will rise.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":31},{"ref":"Mark 9:32","short":"Mar 9:32","text":"But they did not understand what he meant and were afraid to ask him about it.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":32},{"ref":"Mark 9:33","short":"Mar 9:33","text":"They came to Capernaum. When he was in the house, he asked them, \u201cWhat were you arguing about on the road?\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":33},{"ref":"Mark 9:34","short":"Mar 9:34","text":"But they kept quiet because on the way they had argued about who was the greatest.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":34},{"ref":"Mark 9:35","short":"Mar 9:35","text":"Sitting down, Jesus called the Twelve and said, \u201cAnyone who wants to be first must be the very last, and the servant of all.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":35},{"ref":"Mark 9:36","short":"Mar 9:36","text":"He took a little child whom he placed among them. Taking the child in his arms, he said to them,","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":36},{"ref":"Mark 9:37","short":"Mar 9:37","text":"\u201cWhoever welcomes one of these little children in my name welcomes me; and whoever welcomes me does not welcome me but the one who sent me.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":37},{"ref":"Mark 9:38","short":"Mar 9:38","text":"\u201cTeacher,\u201d said John, \u201cwe saw someone driving out demons in your name and we told him to stop, because he was not one of us.\u201d","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":38},{"ref":"Mark 9:39","short":"Mar 9:39","text":"\u201cDo not stop him,\u201d Jesus said. \u201cFor no one who does a miracle in my name can in the next moment say anything bad about me,","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":39},{"ref":"Mark 9:40","short":"Mar 9:40","text":"for whoever is not against us is for us.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":40},{"ref":"Mark 9:41","short":"Mar 9:41","text":"Truly I tell you, anyone who gives you a cup of water in my name because you belong to the Messiah will certainly not lose their reward.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":41},{"ref":"Mark 9:42","short":"Mar 9:42","text":"\u201cIf anyone causes one of these little ones\u2014those who believe in me\u2014to stumble, it would be better for them if a large millstone were hung around their neck and they were thrown into the sea.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":42},{"ref":"Mark 9:43","short":"Mar 9:43","text":"If your hand causes you to stumble, cut it off. It is better for you to enter life maimed than with two hands to go into hell, where the fire never goes out.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":43},{"ref":"Mark 9:45","short":"Mar 9:45","text":"And if your foot causes you to stumble, cut it off. It is better for you to enter life crippled than to have two feet and be thrown into hell.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":45},{"ref":"Mark 9:47","short":"Mar 9:47","text":"And if your eye causes you to stumble, pluck it out. It is better for you to enter the kingdom of God with one eye than to have two eyes and be thrown into hell,","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":47},{"ref":"Mark 9:48","short":"Mar 9:48","text":"where the worms that eat them do not die, and the fire is not quenched.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":48},{"ref":"Mark 9:49","short":"Mar 9:49","text":"Everyone will be salted with fire.","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":49},{"ref":"Mark 9:50","short":"Mar 9:50","text":"&#8220;Salt is good, but if it loses its saltiness, how can you make it salty again? Have salt among yourselves, and be at peace with each other.&#8221;","url":"nt/mark/Mark_9.html","book":"Mark","ch":9,"v":50},{"ref":"Mark 10:1","short":"Mar 10:1","text":"Jesus then left that place and went into the region of Judea and across the Jordan. Again crowds of people came to him, and as was his custom, he taught them.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":1},{"ref":"Mark 10:2","short":"Mar 10:2","text":"Some Pharisees came and tested him by asking, \u201cIs it lawful for a man to divorce his wife?\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":2},{"ref":"Mark 10:3","short":"Mar 10:3","text":"What did Moses command you?\u201d he replied.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":3},{"ref":"Mark 10:4","short":"Mar 10:4","text":"They said, \u201cMoses permitted a man to write a certificate of divorce and send her away.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":4},{"ref":"Mark 10:5","short":"Mar 10:5","text":"\u201cIt was because your hearts were hard that Moses wrote you this law,\u201d Jesus replied.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":5},{"ref":"Mark 10:6","short":"Mar 10:6","text":"But at the beginning of creation God \u201cmade them male and female.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":6},{"ref":"Mark 10:7","short":"Mar 10:7","text":"\u201cFor this reason a man will leave his father and mother and be united to his wife,","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":7},{"ref":"Mark 10:8","short":"Mar 10:8","text":"and the two will become one flesh.\u201d So they are no longer two, but one flesh.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":8},{"ref":"Mark 10:9","short":"Mar 10:9","text":"Therefore what God has joined together, let no one separate.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":9},{"ref":"Mark 10:10","short":"Mar 10:10","text":"When they were in the house again, the disciples asked Jesus about this.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":10},{"ref":"Mark 10:11","short":"Mar 10:11","text":"He answered, \u201cAnyone who divorces his wife and marries another woman commits adultery against her.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":11},{"ref":"Mark 10:12","short":"Mar 10:12","text":"And if she divorces her husband and marries another man, she commits adultery.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":12},{"ref":"Mark 10:13","short":"Mar 10:13","text":"People were bringing little children to Jesus for him to place his hands on them, but the disciples rebuked those who brought them.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":13},{"ref":"Mark 10:14","short":"Mar 10:14","text":"When Jesus saw this, he was indignant. He said to them, \u201cLet the little children come to me, and do not hinder them, for the kingdom of God belongs to such as these.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":14},{"ref":"Mark 10:15","short":"Mar 10:15","text":"Truly I tell you, anyone who will not receive the kingdom of God like a little child will never enter it.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":15},{"ref":"Mark 10:16","short":"Mar 10:16","text":"And he took the children in his arms, placed his hands on them and blessed them.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":16},{"ref":"Mark 10:17","short":"Mar 10:17","text":"As Jesus started on his way, a man ran up to him and fell on his knees before him. \u201cGood teacher,\u201d he asked, \u201cwhat must I do to inherit eternal life?\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":17},{"ref":"Mark 10:18","short":"Mar 10:18","text":"\u201cWhy do you call me good?\u201d Jesus answered. \u201cNo one is good\u2014except God alone.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":18},{"ref":"Mark 10:19","short":"Mar 10:19","text":"You know the commandments: \u201cYou shall not murder, you shall not commit adultery, you shall not steal, you shall not give false testimony, you shall not defraud, honor your father and mother.\u201d\u2019","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":19},{"ref":"Mark 10:20","short":"Mar 10:20","text":"\u201cTeacher,\u201d he declared, \u201call these I have kept since I was a boy.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":20},{"ref":"Mark 10:21","short":"Mar 10:21","text":"Jesus looked at him and loved him. \u201cOne thing you lack,\u201d he said. \u201cGo, sell everything you have and give to the poor, and you will have treasure in heaven. Then come, follow me.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":21},{"ref":"Mark 10:22","short":"Mar 10:22","text":"At this the man\u2019s face fell. He went away sad, because he had great wealth.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":22},{"ref":"Mark 10:23","short":"Mar 10:23","text":"Jesus looked around and said to his disciples, \u201cHow hard it is for the rich to enter the kingdom of God!\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":23},{"ref":"Mark 10:24","short":"Mar 10:24","text":"The disciples were amazed at his words. But Jesus said again, \u201cChildren, how hard it is to enter the kingdom of God!","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":24},{"ref":"Mark 10:25","short":"Mar 10:25","text":"It is easier for a camel to go through the eye of a needle than for someone who is rich to enter the kingdom of God.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":25},{"ref":"Mark 10:26","short":"Mar 10:26","text":"The disciples were even more amazed, and said to each other, \u201cWho then can be saved?\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":26},{"ref":"Mark 10:27","short":"Mar 10:27","text":"Jesus looked at them and said, \u201cWith man this is impossible, but not with God; all things are possible with God.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":27},{"ref":"Mark 10:28","short":"Mar 10:28","text":"Then Peter spoke up, \u201cWe have left everything to follow you!\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":28},{"ref":"Mark 10:29","short":"Mar 10:29","text":"\u201cTruly I tell you,\u201d Jesus replied, \u201cno one who has left home or brothers or sisters or mother or father or children or fields for me and the gospel","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":29},{"ref":"Mark 10:30","short":"Mar 10:30","text":"will fail to receive a hundred times as much in this present age: homes, brothers, sisters, mothers, children and fields\u2014along with persecutions\u2014and in the age to come eternal life.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":30},{"ref":"Mark 10:31","short":"Mar 10:31","text":"But many who are first will be last, and the last first.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":31},{"ref":"Mark 10:32","short":"Mar 10:32","text":"They were on their way up to Jerusalem, with Jesus leading the way, and the disciples were astonished and those who followed were afraid. Again he took the Twelve aside and told them what was going to happen to him.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":32},{"ref":"Mark 10:33","short":"Mar 10:33","text":"\u201cWe are going up to Jerusalem,\u201d he said, \u201cand the Son of Man will be delivered to the chief priests and the teachers of the law. They will condemn him to death and will hand him over to the Gentiles,","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":33},{"ref":"Mark 10:34","short":"Mar 10:34","text":"who will mock him and spit on him, flog him and kill him. Three days later he will rise.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":34},{"ref":"Mark 10:35","short":"Mar 10:35","text":"Then James and John, the sons of Zebedee, came to him. \u201cTeacher,\u201d they said, \u201cwe want you to do for us whatever we ask.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":35},{"ref":"Mark 10:36","short":"Mar 10:36","text":"What do you want me to do for you?\u201d he asked.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":36},{"ref":"Mark 10:37","short":"Mar 10:37","text":"They replied, \u201cLet one of us sit at your right and the other at your left in your glory.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":37},{"ref":"Mark 10:38","short":"Mar 10:38","text":"You don\u2019t know what you are asking,\u201d Jesus said. \u201cCan you drink the cup I drink or be baptized with the baptism I am baptized with?\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":38},{"ref":"Mark 10:39","short":"Mar 10:39","text":"We can,\u201d they answered. Jesus said to them, \u201cYou will drink the cup I drink and be baptized with the baptism I am baptized with,","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":39},{"ref":"Mark 10:40","short":"Mar 10:40","text":"but to sit at my right or left is not for me to grant. These places belong to those for whom they have been prepared.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":40},{"ref":"Mark 10:41","short":"Mar 10:41","text":"When the ten heard about this, they became indignant with James and John.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":41},{"ref":"Mark 10:42","short":"Mar 10:42","text":"Jesus called them together and said, \u201cYou know that those who are regarded as rulers of the Gentiles lord it over them, and their high officials exercise authority over them.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":42},{"ref":"Mark 10:43","short":"Mar 10:43","text":"Not so with you. Instead, whoever wants to become great among you must be your servant,","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":43},{"ref":"Mark 10:44","short":"Mar 10:44","text":"and whoever wants to be first must be slave of all.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":44},{"ref":"Mark 10:45","short":"Mar 10:45","text":"For even the Son of Man did not come to be served, but to serve, and to give his life as a ransom for many.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":45},{"ref":"Mark 10:46","short":"Mar 10:46","text":"Then they came to Jericho. As Jesus and his disciples, together with a large crowd, were leaving the city, a blind man, Bartimaeus (which means \u201cson of Timaeus\u201d), was sitting by the roadside begging.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":46},{"ref":"Mark 10:47","short":"Mar 10:47","text":"When he heard that it was Jesus of Nazareth, he began to shout, \u201cJesus, Son of David, have mercy on me!\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":47},{"ref":"Mark 10:48","short":"Mar 10:48","text":"Many rebuked him and told him to be quiet, but he shouted all the more, \u201cSon of David, have mercy on me!\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":48},{"ref":"Mark 10:49","short":"Mar 10:49","text":"Jesus stopped and said, \u201cCall him.\u201d So they called to the blind man, \u201cCheer up! On your feet! He\u2019s calling you.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":49},{"ref":"Mark 10:50","short":"Mar 10:50","text":"Throwing his cloak aside, he jumped to his feet and came to Jesus.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":50},{"ref":"Mark 10:51","short":"Mar 10:51","text":"What do you want me to do for you?\u201d Jesus asked him. The blind man said, \u201cRabbi, I want to see.\u201d","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":51},{"ref":"Mark 10:52","short":"Mar 10:52","text":"Go,\u201d said Jesus, \u201cyour faith has healed you.\u201d Immediately he received his sight and followed Jesus along the road.","url":"nt/mark/Mark_10.html","book":"Mark","ch":10,"v":52},{"ref":"Mark 11:1","short":"Mar 11:1","text":"As they approached Jerusalem and came to Bethphage and Bethany at the Mount of Olives, Jesus sent two of his disciples,","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":1},{"ref":"Mark 11:2","short":"Mar 11:2","text":"saying to them, \u201cGo to the village ahead of you, and just as you enter it, you will find a colt tied there, which no one has ever ridden. Untie it and bring it here.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":2},{"ref":"Mark 11:3","short":"Mar 11:3","text":"If anyone asks you, \u201cWhy are you doing this?\u201d say, \u201cThe Lord needs it and will send it back here shortly.\u201d\u2019","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":3},{"ref":"Mark 11:4","short":"Mar 11:4","text":"They went and found a colt outside in the street, tied at a doorway. As they untied it,","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":4},{"ref":"Mark 11:5","short":"Mar 11:5","text":"some people standing there asked, \u201cWhat are you doing, untying that colt?\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":5},{"ref":"Mark 11:6","short":"Mar 11:6","text":"They answered as Jesus had told them to, and the people let them go.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":6},{"ref":"Mark 11:7","short":"Mar 11:7","text":"When they brought the colt to Jesus and threw their cloaks over it, he sat on it.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":7},{"ref":"Mark 11:8","short":"Mar 11:8","text":"Many people spread their cloaks on the road, while others spread branches they had cut in the fields.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":8},{"ref":"Mark 11:9","short":"Mar 11:9","text":"Those who went ahead and those who followed shouted, \u201cHosanna!\u201d \u201cBlessed is he who comes in the name of the Lord!\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":9},{"ref":"Mark 11:10","short":"Mar 11:10","text":"\u201cBlessed is the coming kingdom of our father David!\u201d \u201cHosanna in the highest heaven!\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":10},{"ref":"Mark 11:11","short":"Mar 11:11","text":"Jesus entered Jerusalem and went into the temple courts. He looked around at everything, but since it was already late, he went out to Bethany with the Twelve.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":11},{"ref":"Mark 11:12","short":"Mar 11:12","text":"The next morning as they were leaving Bethany, Jesus was hungry.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":12},{"ref":"Mark 11:13","short":"Mar 11:13","text":"Seeing in the distance a fig tree in leaf, he went to find out if it had any fruit. When he reached it, he found nothing but leaves, because it was not the season for figs.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":13},{"ref":"Mark 11:14","short":"Mar 11:14","text":"Then he said to the tree, \u201cMay no one ever eat fruit from you again.\u201d And his disciples heard him say it.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":14},{"ref":"Mark 11:15","short":"Mar 11:15","text":"On reaching Jerusalem, Jesus entered the temple courts and began driving out those who were buying and selling there. He overturned the tables of the money changers and the benches of those selling doves,","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":15},{"ref":"Mark 11:16","short":"Mar 11:16","text":"and would not allow anyone to carry merchandise through the temple courts.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":16},{"ref":"Mark 11:17","short":"Mar 11:17","text":"And as he taught them, he said, \u201cIs it not written: \u201cMy house will be called a house of prayer for all nations\u201d? But you have made it \u201ca den of robbers.\u201d\u2019","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":17},{"ref":"Mark 11:18","short":"Mar 11:18","text":"The chief priests and the teachers of the law heard this and began looking for a way to kill him, for they feared him, because the whole crowd was amazed at his teaching.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":18},{"ref":"Mark 11:19","short":"Mar 11:19","text":"When evening came, Jesus and his disciples went out of the city.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":19},{"ref":"Mark 11:20","short":"Mar 11:20","text":"In the morning, as they went along, they saw the fig tree withered from the roots.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":20},{"ref":"Mark 11:21","short":"Mar 11:21","text":"Peter remembered and said to Jesus, \u201cRabbi, look! The fig tree you cursed has withered!\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":21},{"ref":"Mark 11:22","short":"Mar 11:22","text":"\u201cHave faith in God,\u201d Jesus answered.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":22},{"ref":"Mark 11:23","short":"Mar 11:23","text":"\u201cTruly I tell you, if anyone says to this mountain, \u201cGo, throw yourself into the sea,\u201d and does not doubt in their heart but believes that what they say will happen, it will be done for them.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":23},{"ref":"Mark 11:24","short":"Mar 11:24","text":"Therefore I tell you, whatever you ask for in prayer, believe that you have received it, and it will be yours.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":24},{"ref":"Mark 11:25","short":"Mar 11:25","text":"And when you stand praying, if you hold anything against anyone, forgive them, so that your Father in heaven may forgive you your sins.\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":25},{"ref":"Mark 11:27","short":"Mar 11:27","text":"They arrived again in Jerusalem, and while Jesus was walking in the temple courts, the chief priests, the teachers of the law and the elders came to him.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":27},{"ref":"Mark 11:28","short":"Mar 11:28","text":"\u201cBy what authority are you doing these things?\u201d they asked. \u201cAnd who gave you authority to do this?\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":28},{"ref":"Mark 11:29","short":"Mar 11:29","text":"Jesus replied, \u201cI will ask you one question. Answer me, and I will tell you by what authority I am doing these things.","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":29},{"ref":"Mark 11:30","short":"Mar 11:30","text":"John\u2019s baptism\u2014was it from heaven, or of human origin? Tell me!\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":30},{"ref":"Mark 11:31","short":"Mar 11:31","text":"They discussed it among themselves and said, \u201cIf we say, \u201cFrom heaven,\u201d he will ask, \u201cThen why didn\u2019t you believe him?\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":31},{"ref":"Mark 11:32","short":"Mar 11:32","text":"But if we say, \u201cOf human origin\u201d\u2026\u201d (They feared the people, for everyone held that John really was a prophet.)","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":32},{"ref":"Mark 11:33","short":"Mar 11:33","text":"So they answered Jesus, \u201cWe don\u2019t know.\u201d Jesus said, \u201cNeither will I tell you by what authority I am doing these things.\u201d","url":"nt/mark/Mark_11.html","book":"Mark","ch":11,"v":33},{"ref":"Mark 12:1","short":"Mar 12:1","text":"Jesus then began to speak to them in parables: \u201cA man planted a vineyard. He put a wall around it, dug a pit for the winepress and built a watchtower. Then he rented the vineyard to some farmers and moved to another country.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":1},{"ref":"Mark 12:2","short":"Mar 12:2","text":"At harvest time he sent a servant to the tenants to collect from them some of the fruit of the vineyard.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":2},{"ref":"Mark 12:3","short":"Mar 12:3","text":"But they seized him, beat him and sent him away empty-handed.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":3},{"ref":"Mark 12:4","short":"Mar 12:4","text":"Then he sent another servant to them; they struck this one on the head and treated him shamefully.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":4},{"ref":"Mark 12:5","short":"Mar 12:5","text":"He sent still another, and that one they killed. He sent many others; some of them they beat, others they killed.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":5},{"ref":"Mark 12:6","short":"Mar 12:6","text":"He had one left to send, a son, whom he loved. He sent him last of all, saying, \u201cThey will respect my son.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":6},{"ref":"Mark 12:7","short":"Mar 12:7","text":"\u201cBut the tenants said to one another, \u201cThis is the heir. Come, let\u2019s kill him, and the inheritance will be ours.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":7},{"ref":"Mark 12:8","short":"Mar 12:8","text":"So they took him and killed him, and threw him out of the vineyard.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":8},{"ref":"Mark 12:9","short":"Mar 12:9","text":"What then will the owner of the vineyard do? He will come and kill those tenants and give the vineyard to others.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":9},{"ref":"Mark 12:10","short":"Mar 12:10","text":"Haven\u2019t you read this passage of Scripture: \u201c\u201cThe stone the builders rejected has become the cornerstone;","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":10},{"ref":"Mark 12:11","short":"Mar 12:11","text":"the Lord has done this, and it is marvelous in our eyes\u201d?\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":11},{"ref":"Mark 12:12","short":"Mar 12:12","text":"Then the chief priests, the teachers of the law and the elders looked for a way to arrest him because they knew he had spoken the parable against them. But they were afraid of the crowd; so they left him and went away.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":12},{"ref":"Mark 12:13","short":"Mar 12:13","text":"Later they sent some of the Pharisees and Herodians to Jesus to catch him in his words.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":13},{"ref":"Mark 12:14","short":"Mar 12:14","text":"They came to him and said, \u201cTeacher, we know you are a man of integrity. You aren\u2019t swayed by others, because you pay no attention to who they are; but you teach the way of God in accordance with the truth. Is it right to pay the imperial tax to Caesar or not?","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":14},{"ref":"Mark 12:15","short":"Mar 12:15","text":"Should we pay or shouldn\u2019t we?\u201d But Jesus knew their hypocrisy. \u201cWhy are you trying to trap me?\u201d he asked. \u201cBring me a denarius and let me look at it.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":15},{"ref":"Mark 12:16","short":"Mar 12:16","text":"They brought the coin, and he asked them, \u201cWhose image is this? And whose inscription?\u201d \u201cCaesar\u2019s,\u201d they replied.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":16},{"ref":"Mark 12:17","short":"Mar 12:17","text":"Then Jesus said to them, \u201cGive back to Caesar what is Caesar\u2019s and to God what is God\u2019s.\u201d And they were amazed at him.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":17},{"ref":"Mark 12:18","short":"Mar 12:18","text":"Then the Sadducees, who say there is no resurrection, came to him with a question.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":18},{"ref":"Mark 12:19","short":"Mar 12:19","text":"Teacher,\u201d they said, \u201cMoses wrote for us that if a man\u2019s brother dies and leaves a wife but no children, the man must marry the widow and raise up offspring for his brother.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":19},{"ref":"Mark 12:20","short":"Mar 12:20","text":"Now there were seven brothers. The first one married and died without leaving any children.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":20},{"ref":"Mark 12:21","short":"Mar 12:21","text":"The second one married the widow, but he also died, leaving no child. It was the same with the third.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":21},{"ref":"Mark 12:22","short":"Mar 12:22","text":"In fact, none of the seven left any children. Last of all, the woman died too.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":22},{"ref":"Mark 12:23","short":"Mar 12:23","text":"At the resurrection whose wife will she be, since the seven were married to her?\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":23},{"ref":"Mark 12:24","short":"Mar 12:24","text":"Jesus replied, \u201cAre you not in error because you do not know the Scriptures or the power of God?","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":24},{"ref":"Mark 12:25","short":"Mar 12:25","text":"When the dead rise, they will neither marry nor be given in marriage; they will be like the angels in heaven.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":25},{"ref":"Mark 12:26","short":"Mar 12:26","text":"Now about the dead rising\u2014have you not read in the Book of Moses, in the account of the burning bush, how God said to him, \u201cI am the God of Abraham, the God of Isaac, and the God of Jacob\u201d?","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":26},{"ref":"Mark 12:27","short":"Mar 12:27","text":"He is not the God of the dead, but of the living. You are badly mistaken!\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":27},{"ref":"Mark 12:28","short":"Mar 12:28","text":"One of the teachers of the law came and heard them debating. Noticing that Jesus had given them a good answer, he asked him, \u201cOf all the commandments, which is the most important?\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":28},{"ref":"Mark 12:29","short":"Mar 12:29","text":"\u201cThe most important one,\u201d answered Jesus, \u201cis this: \u201cHear, O Israel: The Lord our God, the Lord is one.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":29},{"ref":"Mark 12:30","short":"Mar 12:30","text":"Love the Lord your God with all your heart and with all your soul and with all your mind and with all your strength.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":30},{"ref":"Mark 12:31","short":"Mar 12:31","text":"The second is this: \u201cLove your neighbor as yourself.\u201d There is no commandment greater than these.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":31},{"ref":"Mark 12:32","short":"Mar 12:32","text":"\u201cWell said, teacher,\u201d the man replied. \u201cYou are right in saying that God is one and there is no other but him.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":32},{"ref":"Mark 12:33","short":"Mar 12:33","text":"To love him with all your heart, with all your understanding and with all your strength, and to love your neighbor as yourself is more important than all burnt offerings and sacrifices.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":33},{"ref":"Mark 12:34","short":"Mar 12:34","text":"When Jesus saw that he had answered wisely, he said to him, \u201cYou are not far from the kingdom of God.\u201d And from then on no one dared ask him any more questions.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":34},{"ref":"Mark 12:35","short":"Mar 12:35","text":"While Jesus was teaching in the temple courts, he asked, \u201cWhy do the teachers of the law say that the Messiah is the Son of David?","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":35},{"ref":"Mark 12:36","short":"Mar 12:36","text":"David himself, speaking by the Holy Spirit, declared: \u201c\u201cThe Lord said to my Lord: \u201cSit at my right hand until I put your enemies under your feet.\u201d\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":36},{"ref":"Mark 12:37","short":"Mar 12:37","text":"David himself calls him \u201cLord.\u201d How then can he be his son?\u201d The large crowd listened to him with delight.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":37},{"ref":"Mark 12:38","short":"Mar 12:38","text":"As he taught, Jesus said, \u201cWatch out for the teachers of the law. They like to walk around in flowing robes and be greeted with respect in the marketplaces,","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":38},{"ref":"Mark 12:39","short":"Mar 12:39","text":"and have the most important seats in the synagogues and the places of honor at banquets.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":39},{"ref":"Mark 12:40","short":"Mar 12:40","text":"They devour widows\u2019 houses and for a show make lengthy prayers. These men will be punished most severely.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":40},{"ref":"Mark 12:41","short":"Mar 12:41","text":"Jesus sat down opposite the place where the offerings were put and watched the crowds putting their money into the temple treasury. Many rich people threw in large amounts.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":41},{"ref":"Mark 12:42","short":"Mar 12:42","text":"But a poor widow came and put in two very small copper coins, worth only a few cents.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":42},{"ref":"Mark 12:43","short":"Mar 12:43","text":"Calling his disciples to him, Jesus said, \u201cTruly I tell you, this poor widow has put more into the treasury than all the others.","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":43},{"ref":"Mark 12:44","short":"Mar 12:44","text":"They all gave out of their wealth; but she, out of her poverty, put in everything\u2014all she had to live on.\u201d","url":"nt/mark/Mark_12.html","book":"Mark","ch":12,"v":44},{"ref":"Mark 13:1","short":"Mar 13:1","text":"As Jesus was leaving the temple, one of his disciples said to him, \u201cLook, Teacher! What massive stones! What magnificent buildings!\u201d","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":1},{"ref":"Mark 13:2","short":"Mar 13:2","text":"\u201cDo you see all these great buildings?\u201d replied Jesus. \u201cNot one stone here will be left on another; every one will be thrown down.\u201d","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":2},{"ref":"Mark 13:3","short":"Mar 13:3","text":"As Jesus was sitting on the Mount of Olives opposite the temple, Peter, James, John and Andrew asked him privately,","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":3},{"ref":"Mark 13:4","short":"Mar 13:4","text":"\u201cTell us, when will these things happen? And what will be the sign that they are all about to be fulfilled?\u201d","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":4},{"ref":"Mark 13:5","short":"Mar 13:5","text":"Jesus said to them: \u201cWatch out that no one deceives you.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":5},{"ref":"Mark 13:6","short":"Mar 13:6","text":"Many will come in my name, claiming, \u201cI am he,\u201d and will deceive many.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":6},{"ref":"Mark 13:7","short":"Mar 13:7","text":"When you hear of wars and rumors of wars, do not be alarmed. Such things must happen, but the end is still to come.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":7},{"ref":"Mark 13:8","short":"Mar 13:8","text":"Nation will rise against nation, and kingdom against kingdom. There will be earthquakes in various places, and famines. These are the beginning of birth pains.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":8},{"ref":"Mark 13:9","short":"Mar 13:9","text":"\u201cYou must be on your guard. You will be handed over to the local councils and flogged in the synagogues. On account of me you will stand before governors and kings as witnesses to them.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":9},{"ref":"Mark 13:10","short":"Mar 13:10","text":"And the gospel must first be preached to all nations.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":10},{"ref":"Mark 13:11","short":"Mar 13:11","text":"Whenever you are arrested and brought to trial, do not worry beforehand about what you will say. Just say whatever is given you at the time, for it is not you speaking, but the Holy Spirit.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":11},{"ref":"Mark 13:12","short":"Mar 13:12","text":"Brother will betray brother to death, and a father his child. Children will rebel against their parents and have them put to death.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":12},{"ref":"Mark 13:13","short":"Mar 13:13","text":"Everyone will hate you because of me, but the one who stands firm to the end will be saved.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":13},{"ref":"Mark 13:14","short":"Mar 13:14","text":"\u201cWhen you see \u201cthe abomination that causes desolation\u201d standing where it does not belong\u2014let the reader understand\u2014then let those who are in Judea flee to the mountains.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":14},{"ref":"Mark 13:15","short":"Mar 13:15","text":"Let no one on the housetop go down or enter the house to take anything out.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":15},{"ref":"Mark 13:16","short":"Mar 13:16","text":"Let no one in the field go back to get their cloak.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":16},{"ref":"Mark 13:17","short":"Mar 13:17","text":"How dreadful it will be in those days for pregnant women and nursing mothers!","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":17},{"ref":"Mark 13:18","short":"Mar 13:18","text":"Pray that this will not take place in winter,","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":18},{"ref":"Mark 13:19","short":"Mar 13:19","text":"because those will be days of distress unequaled from the beginning, when God created the world, until now\u2014and never to be equaled again.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":19},{"ref":"Mark 13:20","short":"Mar 13:20","text":"If the Lord had not cut short those days, no one would survive. But for the sake of the elect, whom he has chosen, he has shortened them.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":20},{"ref":"Mark 13:21","short":"Mar 13:21","text":"At that time if anyone says to you, \u201cLook, here is the Messiah!\u201d or, \u201cLook, there he is!\u201d do not believe it.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":21},{"ref":"Mark 13:22","short":"Mar 13:22","text":"For false messiahs and false prophets will appear and perform signs and wonders to deceive, if possible, even the elect.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":22},{"ref":"Mark 13:23","short":"Mar 13:23","text":"So be on your guard; I have told you everything ahead of time.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":23},{"ref":"Mark 13:24","short":"Mar 13:24","text":"\u201cBut in those days, following that distress, \u201cthe sun will be darkened, and the moon will not give its light;","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":24},{"ref":"Mark 13:25","short":"Mar 13:25","text":"the stars will fall from the sky, and the heavenly bodies will be shaken.\u201d","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":25},{"ref":"Mark 13:26","short":"Mar 13:26","text":"\u201cAt that time people will see the Son of Man coming in clouds with great power and glory.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":26},{"ref":"Mark 13:27","short":"Mar 13:27","text":"And he will send his angels and gather his elect from the four winds, from the ends of the earth to the ends of the heavens.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":27},{"ref":"Mark 13:28","short":"Mar 13:28","text":"\u201cNow learn this lesson from the fig tree: As soon as its twigs get tender and its leaves come out, you know that summer is near.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":28},{"ref":"Mark 13:29","short":"Mar 13:29","text":"Even so, when you see these things happening, you know that it is near, right at the door.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":29},{"ref":"Mark 13:30","short":"Mar 13:30","text":"Truly I tell you, this generation will certainly not pass away until all these things have happened.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":30},{"ref":"Mark 13:31","short":"Mar 13:31","text":"Heaven and earth will pass away, but my words will never pass away.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":31},{"ref":"Mark 13:32","short":"Mar 13:32","text":"\u201cBut about that day or hour no one knows, not even the angels in heaven, nor the Son, but only the Father.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":32},{"ref":"Mark 13:33","short":"Mar 13:33","text":"Be on guard! Be alert! You do not know when that time will come.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":33},{"ref":"Mark 13:34","short":"Mar 13:34","text":"It\u2019s like a man going away: He leaves his house and puts his servants in charge, each with their assigned task, and tells the one at the door to keep watch.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":34},{"ref":"Mark 13:35","short":"Mar 13:35","text":"Therefore keep watch, because you do not know when the owner of the house will come back\u2014whether in the evening, or at midnight, or when the rooster crows, or at dawn.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":35},{"ref":"Mark 13:36","short":"Mar 13:36","text":"If he comes suddenly, do not let him find you sleeping.","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":36},{"ref":"Mark 13:37","short":"Mar 13:37","text":"What I say to you, I say to everyone: \u201cWatch!\u201d","url":"nt/mark/Mark_13.html","book":"Mark","ch":13,"v":37},{"ref":"Mark 14:1","short":"Mar 14:1","text":"Now the Passover and the Festival of Unleavened Bread were only two days away, and the chief priests and the teachers of the law were looking for some sly way to arrest Jesus and kill him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":1},{"ref":"Mark 14:2","short":"Mar 14:2","text":"\u201cBut not during the festival,\u201d they said, \u201cor the people may riot.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":2},{"ref":"Mark 14:3","short":"Mar 14:3","text":"While he was in Bethany, reclining at the table in the home of Simon the Leper, a woman came with an alabaster jar of very expensive perfume, made of pure nard. She broke the jar and poured the perfume on his head.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":3},{"ref":"Mark 14:4","short":"Mar 14:4","text":"Some of those present were saying indignantly to those around them, \u201cWhy this waste of perfume?","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":4},{"ref":"Mark 14:5","short":"Mar 14:5","text":"It could have been sold for more than a year\u2019s wages and the money given to the poor.\u201d And they rebuked her harshly.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":5},{"ref":"Mark 14:6","short":"Mar 14:6","text":"Leave her alone,\u201d said Jesus. \u201cWhy are you bothering her? She has done a beautiful thing to me.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":6},{"ref":"Mark 14:7","short":"Mar 14:7","text":"The poor you will always have with you, and you can help them any time you want. But you will not always have me.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":7},{"ref":"Mark 14:8","short":"Mar 14:8","text":"She did what she could. She poured perfume on my body beforehand to prepare for my burial.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":8},{"ref":"Mark 14:9","short":"Mar 14:9","text":"Truly I tell you, wherever the gospel is preached throughout the world, what she has done will also be told, in memory of her.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":9},{"ref":"Mark 14:10","short":"Mar 14:10","text":"Then Judas Iscariot, one of the Twelve, went to the chief priests to betray Jesus to them.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":10},{"ref":"Mark 14:11","short":"Mar 14:11","text":"They were delighted to hear this and promised to give him money. So he watched for an opportunity to hand him over.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":11},{"ref":"Mark 14:12","short":"Mar 14:12","text":"On the first day of the Festival of Unleavened Bread, when it was customary to sacrifice the Passover lamb, his disciples asked him, \u201cWhere do you want us to go and make preparations for you to eat the Passover?\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":12},{"ref":"Mark 14:13","short":"Mar 14:13","text":"So he sent two of his disciples, telling them, \u201cGo into the city, and a man carrying a jar of water will meet you. Follow him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":13},{"ref":"Mark 14:14","short":"Mar 14:14","text":"Say to the owner of the house he enters, \u201cThe Teacher asks: Where is my guest room, where I may eat the Passover with my disciples?\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":14},{"ref":"Mark 14:15","short":"Mar 14:15","text":"He will show you a large room upstairs, furnished and ready. Make preparations for us there.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":15},{"ref":"Mark 14:16","short":"Mar 14:16","text":"The disciples left, went into the city and found things just as Jesus had told them. So they prepared the Passover.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":16},{"ref":"Mark 14:17","short":"Mar 14:17","text":"When evening came, Jesus arrived with the Twelve.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":17},{"ref":"Mark 14:18","short":"Mar 14:18","text":"While they were reclining at the table eating, he said, \u201cTruly I tell you, one of you will betray me\u2014one who is eating with me.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":18},{"ref":"Mark 14:19","short":"Mar 14:19","text":"They were saddened, and one by one they said to him, \u201cSurely you don\u2019t mean me?\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":19},{"ref":"Mark 14:20","short":"Mar 14:20","text":"\u201cIt is one of the Twelve,\u201d he replied, \u201cone who dips bread into the bowl with me.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":20},{"ref":"Mark 14:21","short":"Mar 14:21","text":"The Son of Man will go just as it is written about him. But woe to that man who betrays the Son of Man! It would be better for him if he had not been born.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":21},{"ref":"Mark 14:22","short":"Mar 14:22","text":"While they were eating, Jesus took bread, and when he had given thanks, he broke it and gave it to his disciples, saying, \u201cTake it; this is my body.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":22},{"ref":"Mark 14:23","short":"Mar 14:23","text":"Then he took a cup, and when he had given thanks, he gave it to them, and they all drank from it.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":23},{"ref":"Mark 14:24","short":"Mar 14:24","text":"\u201cThis is my blood of the covenant, which is poured out for many,\u201d he said to them.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":24},{"ref":"Mark 14:25","short":"Mar 14:25","text":"\u201cTruly I tell you, I will not drink again from the fruit of the vine until that day when I drink it new in the kingdom of God.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":25},{"ref":"Mark 14:26","short":"Mar 14:26","text":"When they had sung a hymn, they went out to the Mount of Olives.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":26},{"ref":"Mark 14:27","short":"Mar 14:27","text":"\u201cYou will all fall away,\u201d Jesus told them, \u201cfor it is written: \u201c\u201cI will strike the shepherd, and the sheep will be scattered.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":27},{"ref":"Mark 14:28","short":"Mar 14:28","text":"But after I have risen, I will go ahead of you into Galilee.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":28},{"ref":"Mark 14:29","short":"Mar 14:29","text":"Peter declared, \u201cEven if all fall away, I will not.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":29},{"ref":"Mark 14:30","short":"Mar 14:30","text":"\u201cTruly I tell you,\u201d Jesus answered, \u201ctoday\u2014yes, tonight\u2014before the rooster crows twice you yourself will disown me three times.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":30},{"ref":"Mark 14:31","short":"Mar 14:31","text":"But Peter insisted emphatically, \u201cEven if I have to die with you, I will never disown you.\u201d And all the others said the same.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":31},{"ref":"Mark 14:32","short":"Mar 14:32","text":"They went to a place called Gethsemane, and Jesus said to his disciples, \u201cSit here while I pray.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":32},{"ref":"Mark 14:33","short":"Mar 14:33","text":"He took Peter, James and John along with him, and he began to be deeply distressed and troubled.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":33},{"ref":"Mark 14:34","short":"Mar 14:34","text":"\u201cMy soul is overwhelmed with sorrow to the point of death,\u201d he said to them. \u201cStay here and keep watch.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":34},{"ref":"Mark 14:35","short":"Mar 14:35","text":"Going a little farther, he fell to the ground and prayed that if possible the hour might pass from him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":35},{"ref":"Mark 14:36","short":"Mar 14:36","text":"\u201cAbba, Father,\u201d he said, \u201ceverything is possible for you. Take this cup from me. Yet not what I will, but what you will.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":36},{"ref":"Mark 14:37","short":"Mar 14:37","text":"Then he returned to his disciples and found them sleeping. \u201cSimon,\u201d he said to Peter, \u201ccould you not keep watch for one hour?","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":37},{"ref":"Mark 14:38","short":"Mar 14:38","text":"Watch and pray so that you will not fall into temptation. The spirit is willing, but the flesh is weak.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":38},{"ref":"Mark 14:39","short":"Mar 14:39","text":"Once more he went away and prayed the same thing.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":39},{"ref":"Mark 14:40","short":"Mar 14:40","text":"When he came back, he again found them sleeping, because their eyes were heavy. They did not know what to say to him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":40},{"ref":"Mark 14:41","short":"Mar 14:41","text":"Returning the third time, he said to them, \u201cAre you still sleeping and resting? Enough! The hour has come. Look, the Son of Man is delivered into the hands of sinners.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":41},{"ref":"Mark 14:42","short":"Mar 14:42","text":"Rise! Let us go! Here comes my betrayer!\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":42},{"ref":"Mark 14:43","short":"Mar 14:43","text":"Just as he was speaking, Judas, one of the Twelve, appeared. With him was a crowd armed with swords and clubs, sent from the chief priests, the teachers of the law, and the elders.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":43},{"ref":"Mark 14:44","short":"Mar 14:44","text":"Now the betrayer had arranged a signal with them: \u201cThe one I kiss is the man; arrest him and lead him away under guard.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":44},{"ref":"Mark 14:45","short":"Mar 14:45","text":"Going at once to Jesus, Judas said, \u201cRabbi!\u201d and kissed him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":45},{"ref":"Mark 14:46","short":"Mar 14:46","text":"The men seized Jesus and arrested him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":46},{"ref":"Mark 14:47","short":"Mar 14:47","text":"Then one of those standing near drew his sword and struck the servant of the high priest, cutting off his ear.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":47},{"ref":"Mark 14:48","short":"Mar 14:48","text":"\u201cAm I leading a rebellion,\u201d said Jesus, \u201cthat you have come out with swords and clubs to capture me?","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":48},{"ref":"Mark 14:49","short":"Mar 14:49","text":"Every day I was with you, teaching in the temple courts, and you did not arrest me. But the Scriptures must be fulfilled.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":49},{"ref":"Mark 14:50","short":"Mar 14:50","text":"Then everyone deserted him and fled.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":50},{"ref":"Mark 14:51","short":"Mar 14:51","text":"A young man, wearing nothing but a linen garment, was following Jesus. When they seized him,","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":51},{"ref":"Mark 14:52","short":"Mar 14:52","text":"he fled naked, leaving his garment behind.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":52},{"ref":"Mark 14:53","short":"Mar 14:53","text":"They took Jesus to the high priest, and all the chief priests, the elders and the teachers of the law came together.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":53},{"ref":"Mark 14:54","short":"Mar 14:54","text":"Peter followed him at a distance, right into the courtyard of the high priest. There he sat with the guards and warmed himself at the fire.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":54},{"ref":"Mark 14:55","short":"Mar 14:55","text":"The chief priests and the whole Sanhedrin were looking for evidence against Jesus so that they could put him to death, but they did not find any.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":55},{"ref":"Mark 14:56","short":"Mar 14:56","text":"Many testified falsely against him, but their statements did not agree.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":56},{"ref":"Mark 14:57","short":"Mar 14:57","text":"Then some stood up and gave this false testimony against him:","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":57},{"ref":"Mark 14:58","short":"Mar 14:58","text":"\u201cWe heard him say, \u201cI will destroy this temple made with human hands and in three days will build another, not made with hands.\u201d\u2019","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":58},{"ref":"Mark 14:59","short":"Mar 14:59","text":"Yet even then their testimony did not agree.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":59},{"ref":"Mark 14:60","short":"Mar 14:60","text":"Then the high priest stood up before them and asked Jesus, \u201cAre you not going to answer? What is this testimony that these men are bringing against you?\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":60},{"ref":"Mark 14:61","short":"Mar 14:61","text":"But Jesus remained silent and gave no answer. Again the high priest asked him, \u201cAre you the Messiah, the Son of the Blessed One?\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":61},{"ref":"Mark 14:62","short":"Mar 14:62","text":"\u201cI am,\u201d said Jesus. \u201cAnd you will see the Son of Man sitting at the right hand of the Mighty One and coming on the clouds of heaven.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":62},{"ref":"Mark 14:63","short":"Mar 14:63","text":"The high priest tore his clothes. \u201cWhy do we need any more witnesses?\u201d he said.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":63},{"ref":"Mark 14:64","short":"Mar 14:64","text":"You have heard the blasphemy. What do you think?\u201d They all condemned him as worthy of death.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":64},{"ref":"Mark 14:65","short":"Mar 14:65","text":"Then some began to spit at him; they blindfolded him, struck him with their fists, and said, \u201cProphesy!\u201d And the guards took him and beat him.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":65},{"ref":"Mark 14:66","short":"Mar 14:66","text":"While Peter was below in the courtyard, one of the servant girls of the high priest came by.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":66},{"ref":"Mark 14:67","short":"Mar 14:67","text":"When she saw Peter warming himself, she looked closely at him. \u201cYou also were with that Nazarene, Jesus,\u201d she said.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":67},{"ref":"Mark 14:68","short":"Mar 14:68","text":"But he denied it. \u201cI don\u2019t know or understand what you\u2019re talking about,\u201d he said, and went out into the entryway.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":68},{"ref":"Mark 14:69","short":"Mar 14:69","text":"When the servant girl saw him there, she said again to those standing around, \u201cThis fellow is one of them.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":69},{"ref":"Mark 14:70","short":"Mar 14:70","text":"Again he denied it. After a little while, those standing near said to Peter, \u201cSurely you are one of them, for you are a Galilean.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":70},{"ref":"Mark 14:71","short":"Mar 14:71","text":"He began to call down curses, and he swore to them, \u201cI don\u2019t know this man you\u2019re talking about.\u201d","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":71},{"ref":"Mark 14:72","short":"Mar 14:72","text":"Immediately the rooster crowed the second time. Then Peter remembered the word Jesus had spoken to him: \u201cBefore the rooster crows twice you will disown me three times.\u201d And he broke down and wept.","url":"nt/mark/Mark_14.html","book":"Mark","ch":14,"v":72},{"ref":"Mark 15:1","short":"Mar 15:1","text":"Very early in the morning, the chief priests, with the elders, the teachers of the law and the whole Sanhedrin, made their plans. They bound Jesus, led him away and handed him over to Pilate.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":1},{"ref":"Mark 15:2","short":"Mar 15:2","text":"\u201cAre you the king of the Jews?\u201d asked Pilate. \u201cYou have said so,\u201d Jesus replied.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":2},{"ref":"Mark 15:3","short":"Mar 15:3","text":"The chief priests accused him of many things.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":3},{"ref":"Mark 15:4","short":"Mar 15:4","text":"So again Pilate asked him, \u201cAren\u2019t you going to answer? See how many things they are accusing you of.\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":4},{"ref":"Mark 15:5","short":"Mar 15:5","text":"But Jesus still made no reply, and Pilate was amazed.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":5},{"ref":"Mark 15:6","short":"Mar 15:6","text":"Now it was the custom at the festival to release a prisoner whom the people requested.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":6},{"ref":"Mark 15:7","short":"Mar 15:7","text":"A man called Barabbas was in prison with the insurrectionists who had committed murder in the uprising.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":7},{"ref":"Mark 15:8","short":"Mar 15:8","text":"The crowd came up and asked Pilate to do for them what he usually did.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":8},{"ref":"Mark 15:9","short":"Mar 15:9","text":"\u201cDo you want me to release to you the king of the Jews?\u201d asked Pilate,","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":9},{"ref":"Mark 15:10","short":"Mar 15:10","text":"knowing it was out of self-interest that the chief priests had handed Jesus over to him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":10},{"ref":"Mark 15:11","short":"Mar 15:11","text":"But the chief priests stirred up the crowd to have Pilate release Barabbas instead.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":11},{"ref":"Mark 15:12","short":"Mar 15:12","text":"\u201cWhat shall I do, then, with the one you call the king of the Jews?\u201d Pilate asked them.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":12},{"ref":"Mark 15:13","short":"Mar 15:13","text":"\u201cCrucify him!\u201d they shouted.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":13},{"ref":"Mark 15:14","short":"Mar 15:14","text":"\u201cWhy? What crime has he committed?\u201d asked Pilate. But they shouted all the louder, \u201cCrucify him!\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":14},{"ref":"Mark 15:15","short":"Mar 15:15","text":"Wanting to satisfy the crowd, Pilate released Barabbas to them. He had Jesus flogged, and handed him over to be crucified.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":15},{"ref":"Mark 15:16","short":"Mar 15:16","text":"The soldiers led Jesus away into the palace (that is, the Praetorium) and called together the whole company of soldiers.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":16},{"ref":"Mark 15:17","short":"Mar 15:17","text":"They put a purple robe on him, then twisted together a crown of thorns and set it on him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":17},{"ref":"Mark 15:18","short":"Mar 15:18","text":"And they began to call out to him, \u201cHail, king of the Jews!\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":18},{"ref":"Mark 15:19","short":"Mar 15:19","text":"Again and again they struck him on the head with a staff and spit on him. Falling on their knees, they paid homage to him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":19},{"ref":"Mark 15:20","short":"Mar 15:20","text":"And when they had mocked him, they took off the purple robe and put his own clothes on him. Then they led him out to crucify him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":20},{"ref":"Mark 15:21","short":"Mar 15:21","text":"A certain man from Cyrene, Simon the father of Alexander and Rufus, was passing by on his way in from the country, and they forced him to carry the cross.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":21},{"ref":"Mark 15:22","short":"Mar 15:22","text":"They brought Jesus to the place called Golgotha (which means \u201cthe place of the skull\u201d).","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":22},{"ref":"Mark 15:23","short":"Mar 15:23","text":"Then they offered him wine mixed with myrrh, but he did not take it.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":23},{"ref":"Mark 15:24","short":"Mar 15:24","text":"And they crucified him. Dividing up his clothes, they cast lots to see what each would get.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":24},{"ref":"Mark 15:25","short":"Mar 15:25","text":"It was nine in the morning when they crucified him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":25},{"ref":"Mark 15:26","short":"Mar 15:26","text":"The written notice of the charge against him read: the king of the jews.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":26},{"ref":"Mark 15:27","short":"Mar 15:27","text":"They crucified two rebels with him, one on his right and one on his left.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":27},{"ref":"Mark 15:29","short":"Mar 15:29","text":"Those who passed by hurled insults at him, shaking their heads and saying, \u201cSo! You who are going to destroy the temple and build it in three days,","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":29},{"ref":"Mark 15:30","short":"Mar 15:30","text":"come down from the cross and save yourself!\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":30},{"ref":"Mark 15:31","short":"Mar 15:31","text":"In the same way the chief priests and the teachers of the law mocked him among themselves. \u201cHe saved others,\u201d they said, \u201cbut he can\u2019t save himself!","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":31},{"ref":"Mark 15:32","short":"Mar 15:32","text":"Let this Messiah, this king of Israel, come down now from the cross, that we may see and believe.\u201d Those crucified with him also heaped insults on him.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":32},{"ref":"Mark 15:33","short":"Mar 15:33","text":"At noon, darkness came over the whole land until three in the afternoon.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":33},{"ref":"Mark 15:34","short":"Mar 15:34","text":"And at three in the afternoon Jesus cried out in a loud voice, \u201cEloi, Eloi, lema sabachthani?\u201d (which means \u201cMy God, my God, why have you forsaken me?\u201d).","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":34},{"ref":"Mark 15:35","short":"Mar 15:35","text":"When some of those standing near heard this, they said, \u201cListen, he\u2019s calling Elijah.\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":35},{"ref":"Mark 15:36","short":"Mar 15:36","text":"Someone ran, filled a sponge with wine vinegar, put it on a staff, and offered it to Jesus to drink. \u201cNow leave him alone. Let\u2019s see if Elijah comes to take him down,\u201d he said.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":36},{"ref":"Mark 15:37","short":"Mar 15:37","text":"With a loud cry, Jesus breathed his last.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":37},{"ref":"Mark 15:38","short":"Mar 15:38","text":"The curtain of the temple was torn in two from top to bottom.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":38},{"ref":"Mark 15:39","short":"Mar 15:39","text":"And when the centurion, who stood there in front of Jesus, saw how he died, he said, \u201cSurely this man was the Son of God!\u201d","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":39},{"ref":"Mark 15:40","short":"Mar 15:40","text":"Some women were watching from a distance. Among them were Mary Magdalene, Mary the mother of James the younger and of Joseph, and Salome.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":40},{"ref":"Mark 15:41","short":"Mar 15:41","text":"In Galilee these women had followed him and cared for his needs. Many other women who had come up with him to Jerusalem were also there.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":41},{"ref":"Mark 15:42","short":"Mar 15:42","text":"It was Preparation Day (that is, the day before the Sabbath). So as evening approached,","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":42},{"ref":"Mark 15:43","short":"Mar 15:43","text":"Joseph of Arimathea, a prominent member of the Council, who was himself waiting for the kingdom of God, went boldly to Pilate and asked for Jesus\u2019 body.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":43},{"ref":"Mark 15:44","short":"Mar 15:44","text":"Pilate was surprised that he was already dead. Summoning the centurion, he asked him if Jesus had already died.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":44},{"ref":"Mark 15:45","short":"Mar 15:45","text":"When he learned from the centurion that it was so, he gave the body to Joseph.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":45},{"ref":"Mark 15:46","short":"Mar 15:46","text":"So Joseph bought some linen cloth, took down the body, wrapped it in the linen, and placed it in a tomb cut out of rock. Then he rolled a stone against the entrance of the tomb.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":46},{"ref":"Mark 15:47","short":"Mar 15:47","text":"Mary Magdalene and Mary the mother of Joseph saw where he was laid.","url":"nt/mark/Mark_15.html","book":"Mark","ch":15,"v":47},{"ref":"Mark 16:1","short":"Mar 16:1","text":"When the Sabbath was over, Mary Magdalene, Mary the mother of James, and Salome bought spices so that they might go to anoint Jesus\u2019 body.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":1},{"ref":"Mark 16:2","short":"Mar 16:2","text":"Very early on the first day of the week, just after sunrise, they were on their way to the tomb","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":2},{"ref":"Mark 16:3","short":"Mar 16:3","text":"and they asked each other, \u201cWho will roll the stone away from the entrance of the tomb?\u201d","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":3},{"ref":"Mark 16:4","short":"Mar 16:4","text":"But when they looked up, they saw that the stone, which was very large, had been rolled away.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":4},{"ref":"Mark 16:5","short":"Mar 16:5","text":"As they entered the tomb, they saw a young man dressed in a white robe sitting on the right side, and they were alarmed.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":5},{"ref":"Mark 16:6","short":"Mar 16:6","text":"\u201cDon\u2019t be alarmed,\u201d he said. \u201cYou are looking for Jesus the Nazarene, who was crucified. He has risen! He is not here. See the place where they laid him.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":6},{"ref":"Mark 16:7","short":"Mar 16:7","text":"But go, tell his disciples and Peter, \u201cHe is going ahead of you into Galilee. There you will see him, just as he told you.\u201d\u2019","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":7},{"ref":"Mark 16:8","short":"Mar 16:8","text":"Trembling and bewildered, the women went out and fled from the tomb. They said nothing to anyone, because they were afraid.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":8},{"ref":"Mark 16:9","short":"Mar 16:9","text":"When Jesus rose early on the first day of the week, he appeared first to Mary Magdalene, out of whom he had driven seven demons.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":9},{"ref":"Mark 16:10","short":"Mar 16:10","text":"She went and told those who had been with him and who were mourning and weeping.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":10},{"ref":"Mark 16:11","short":"Mar 16:11","text":"When they heard that Jesus was alive and that she had seen him, they did not believe it.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":11},{"ref":"Mark 16:12","short":"Mar 16:12","text":"Afterward Jesus appeared in a different form to two of them while they were walking in the country.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":12},{"ref":"Mark 16:13","short":"Mar 16:13","text":"These returned and reported it to the rest; but they did not believe them either.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":13},{"ref":"Mark 16:14","short":"Mar 16:14","text":"Later Jesus appeared to the Eleven as they were eating; he rebuked them for their lack of faith and their stubborn refusal to believe those who had seen him after he had risen.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":14},{"ref":"Mark 16:15","short":"Mar 16:15","text":"He said to them, \u201cGo into all the world and preach the gospel to all creation.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":15},{"ref":"Mark 16:16","short":"Mar 16:16","text":"Whoever believes and is baptized will be saved, but whoever does not believe will be condemned.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":16},{"ref":"Mark 16:17","short":"Mar 16:17","text":"And these signs will accompany those who believe: In my name they will drive out demons; they will speak in new tongues;","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":17},{"ref":"Mark 16:18","short":"Mar 16:18","text":"they will pick up snakes with their hands; and when they drink deadly poison, it will not hurt them at all; they will place their hands on sick people, and they will get well.\u201d","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":18},{"ref":"Mark 16:19","short":"Mar 16:19","text":"After the Lord Jesus had spoken to them, he was taken up into heaven and he sat at the right hand of God.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":19},{"ref":"Mark 16:20","short":"Mar 16:20","text":"Then the disciples went out and preached everywhere, and the Lord worked with them and confirmed his word by the signs that accompanied it.","url":"nt/mark/Mark_16.html","book":"Mark","ch":16,"v":20}];
if(!window.VERSES_ALL)window.VERSES_ALL=[];
window.VERSES_ALL=window.VERSES_ALL.concat(VERSES_MARK);
